/**
 * Title: Ice Crystals
 * Description: Hexagonal crystal growth with 6-fold symmetry, prismatic highlights, and mouse-warmth melting.
 */
const CONFIG = {
	maxCrystals: 8,
	growthSpeed: 0.8,
	branchProb: 0.3,
	branchAngle: Math.PI / 3,
	maxDepth: 4,
	symmetry: 6,
	color: 'rgba(180,220,255,',
	prismIntensity: 0.6,
	meltRadius: 120,
	meltSpeed: 0.02,
	regrowDelay: 90,
	edgeFrost: 40,
	seedInterval: 200
};
let canvas,
	ctx,
	W,
	H,
	mouse = { x: -5e3, y: -5e3 },
	crystals = [],
	time = 0;
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1e3);
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			W = e.data.width;
			H = e.data.height;
			canvas.width = W;
			canvas.height = H;
			startAnim();
			break;
		case 'resize':
			W = e.data.width;
			H = e.data.height;
			canvas.width = W;
			canvas.height = H;
			crystals = [];
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};
class Crystal {
	constructor(x, y) {
		this.x = x;
		this.y = y;
		this.segs = [];
		this.queue = [{ x, y, angle: 0, depth: 0, len: 0, maxLen: 20 + Math.random() * 30 }];
		for (let i = 1; i < CONFIG.symmetry; i++)
			this.queue.push({
				x,
				y,
				angle: ((Math.PI * 2) / CONFIG.symmetry) * i,
				depth: 0,
				len: 0,
				maxLen: 20 + Math.random() * 30
			});
		this.melted = 0;
		this.meltTimer = 0;
	}
	grow(dt) {
		if (this.melted > 0) {
			this.meltTimer++;
			if (this.meltTimer > CONFIG.regrowDelay) this.melted = Math.max(0, this.melted - 0.01 * dt);
			return;
		}
		let newQ = [];
		for (let q of this.queue) {
			if (q.len < q.maxLen) {
				q.len += CONFIG.growthSpeed * dt;
				let ex = q.x + Math.cos(q.angle) * q.len,
					ey = q.y + Math.sin(q.angle) * q.len;
				this.segs.push({
					x1: q.x,
					y1: q.y,
					x2: ex,
					y2: ey,
					d: q.depth,
					hue: ((q.angle * 180) / Math.PI + time * 0.5) % 360
				});
				if (q.len >= q.maxLen && q.depth < CONFIG.maxDepth && Math.random() < CONFIG.branchProb) {
					let a1 = q.angle + CONFIG.branchAngle * (0.8 + Math.random() * 0.4),
						a2 = q.angle - CONFIG.branchAngle * (0.8 + Math.random() * 0.4);
					let ml = q.maxLen * 0.65;
					newQ.push({ x: ex, y: ey, angle: a1, depth: q.depth + 1, len: 0, maxLen: ml });
					newQ.push({ x: ex, y: ey, angle: a2, depth: q.depth + 1, len: 0, maxLen: ml });
				} else if (q.len < q.maxLen) {
					newQ.push(q);
				}
			}
		}
		this.queue = newQ;
	}
	draw() {
		let s = 1 - this.melted;
		for (let seg of this.segs) {
			let a = Math.max(0.05, (0.6 - seg.d * 0.1) * s);
			ctx.strokeStyle =
				CONFIG.prismIntensity > 0
					? `hsla(${seg.hue},70%,80%,${a * CONFIG.prismIntensity})`
					: CONFIG.color + a + ')';
			ctx.lineWidth = Math.max(0.5, (3 - seg.d * 0.5) * s);
			ctx.beginPath();
			ctx.moveTo(seg.x1, seg.y1);
			ctx.lineTo(seg.x2, seg.y2);
			ctx.stroke();
		}
	}
	melt(amt) {
		this.melted = Math.min(1, this.melted + amt);
		this.meltTimer = 0;
	}
}
function drawFrost() {
	ctx.globalAlpha = 0.08;
	let g = ctx.createLinearGradient(0, 0, CONFIG.edgeFrost, 0);
	g.addColorStop(0, 'rgba(200,230,255,0.4)');
	g.addColorStop(1, 'transparent');
	ctx.fillStyle = g;
	ctx.fillRect(0, 0, CONFIG.edgeFrost, H);
	let g2 = ctx.createLinearGradient(W, 0, W - CONFIG.edgeFrost, 0);
	g2.addColorStop(0, 'rgba(200,230,255,0.4)');
	g2.addColorStop(1, 'transparent');
	ctx.fillStyle = g2;
	ctx.fillRect(W - CONFIG.edgeFrost, 0, CONFIG.edgeFrost, H);
	let g3 = ctx.createLinearGradient(0, 0, 0, CONFIG.edgeFrost);
	g3.addColorStop(0, 'rgba(200,230,255,0.4)');
	g3.addColorStop(1, 'transparent');
	ctx.fillStyle = g3;
	ctx.fillRect(0, 0, W, CONFIG.edgeFrost);
	ctx.globalAlpha = 1;
}
function startAnim() {
	let last = performance.now();
	function render(now) {
		if (!ctx) return;
		let dt = Math.min((now - last) / 16.67, 3);
		last = now;
		time++;
		ctx.clearRect(0, 0, W, H);
		if (time % CONFIG.seedInterval === 0 && crystals.length < CONFIG.maxCrystals) {
			crystals.push(new Crystal(Math.random() * W, Math.random() * H));
		}
		for (let c of crystals) {
			let dx = c.x - mouse.x,
				dy = c.y - mouse.y,
				d = Math.sqrt(dx * dx + dy * dy);
			if (d < CONFIG.meltRadius) c.melt(CONFIG.meltSpeed * dt * (1 - d / CONFIG.meltRadius));
			c.grow(dt);
			c.draw();
		}
		drawFrost();
		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Ink Bloom
 * Description: Ink-drop-like blooms that slowly expand and diffuse at random
 *   locations, fading out as they grow. Deep, rich colors (indigo, crimson,
 *   emerald) with low opacity. Mouse position influences where new blooms appear.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let blooms = [];
let time = 0;
let lastBloomTime = 0;

const MAX_BLOOMS = 25;
const BLOOM_INTERVAL = 80; // frames between new blooms
const MOUSE_BLOOM_CHANCE = 0.4; // chance a bloom spawns near mouse

// Heartbeat to keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// Deep, rich color palette
const COLORS = [
	{ r: 40, g: 20, b: 120 }, // deep indigo
	{ r: 150, g: 15, b: 30 }, // crimson
	{ r: 10, g: 100, b: 60 }, // emerald
	{ r: 80, g: 10, b: 110 }, // dark violet
	{ r: 20, g: 60, b: 120 }, // navy blue
	{ r: 120, g: 30, b: 80 }, // plum
	{ r: 10, g: 80, b: 90 } // teal
];

class Bloom {
	constructor(x, y) {
		this.x = x;
		this.y = y;
		this.radius = 2;
		this.maxRadius = 80 + Math.random() * 160;
		this.growthRate = 0.3 + Math.random() * 0.5;
		this.color = COLORS[Math.floor(Math.random() * COLORS.length)];
		this.alpha = 0.08 + Math.random() * 0.05;
		this.maxAlpha = this.alpha;
		this.alive = true;
		this.age = 0;
		this.rotation = Math.random() * Math.PI * 2;
		this.rotationSpeed = (Math.random() - 0.5) * 0.002;
		// Slight organic drift
		this.driftX = (Math.random() - 0.5) * 0.15;
		this.driftY = (Math.random() - 0.5) * 0.15;
		// Number of tendrils for the ink bloom shape
		this.tendrils = 5 + Math.floor(Math.random() * 4);
		this.tendrilPhases = [];
		this.tendrilAmps = [];
		for (let i = 0; i < this.tendrils; i++) {
			this.tendrilPhases.push(Math.random() * Math.PI * 2);
			this.tendrilAmps.push(0.15 + Math.random() * 0.25);
		}
	}

	update() {
		this.age++;
		this.radius += this.growthRate * (1 - this.radius / this.maxRadius);
		this.rotation += this.rotationSpeed;
		this.x += this.driftX;
		this.y += this.driftY;

		// Fade as bloom approaches max size
		const progress = this.radius / this.maxRadius;
		if (progress > 0.5) {
			this.alpha = this.maxAlpha * (1 - (progress - 0.5) * 2);
		}

		if (this.alpha <= 0.001 || this.radius >= this.maxRadius * 0.98) {
			this.alive = false;
		}
	}

	draw() {
		const { r, g, b } = this.color;

		ctx.save();
		ctx.translate(this.x, this.y);
		ctx.rotate(this.rotation);

		// Draw multiple concentric bloom layers for depth
		for (let layer = 0; layer < 4; layer++) {
			const layerScale = 0.4 + layer * 0.2;
			const layerAlpha = this.alpha * (1 - layer * 0.2);
			const rad = this.radius * layerScale;

			if (layerAlpha <= 0) continue;

			// Organic ink shape using overlapping radial gradients with offset
			const offsetX = Math.sin(this.age * 0.02 + layer) * rad * 0.1;
			const offsetY = Math.cos(this.age * 0.02 + layer * 1.5) * rad * 0.1;

			const gradient = ctx.createRadialGradient(offsetX, offsetY, 0, offsetX, offsetY, rad);
			gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${layerAlpha})`);
			gradient.addColorStop(0.3, `rgba(${r}, ${g}, ${b}, ${layerAlpha * 0.7})`);
			gradient.addColorStop(0.6, `rgba(${r}, ${g}, ${b}, ${layerAlpha * 0.3})`);
			gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);

			// Draw an organic, ink-like shape
			ctx.beginPath();
			const steps = 60;
			for (let i = 0; i <= steps; i++) {
				const angle = (i / steps) * Math.PI * 2;
				let r2 = rad;
				// Add tendril distortion
				for (let t = 0; t < this.tendrils; t++) {
					r2 +=
						Math.sin(angle * (t + 2) + this.tendrilPhases[t] + this.age * 0.008) *
						rad *
						this.tendrilAmps[t] *
						layerScale;
				}
				const px = Math.cos(angle) * r2;
				const py = Math.sin(angle) * r2;
				if (i === 0) {
					ctx.moveTo(px, py);
				} else {
					ctx.lineTo(px, py);
				}
			}
			ctx.closePath();
			ctx.fillStyle = gradient;
			ctx.fill();
		}

		ctx.restore();
	}
}

function spawnBloom() {
	let x, y;
	const nearMouse = mouse.x > 0 && mouse.y > 0 && Math.random() < MOUSE_BLOOM_CHANCE;

	if (nearMouse) {
		// Spawn near mouse with some scatter
		x = mouse.x + (Math.random() - 0.5) * 200;
		y = mouse.y + (Math.random() - 0.5) * 200;
	} else {
		x = Math.random() * width;
		y = Math.random() * height;
	}

	blooms.push(new Bloom(x, y));
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			blooms = [];
			// Seed initial blooms
			for (let i = 0; i < 5; i++) {
				spawnBloom();
			}
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;

		// Slow fade for trailing ink effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.015)';
		ctx.fillRect(0, 0, width, height);

		time++;

		// Spawn new blooms periodically
		if (time - lastBloomTime > BLOOM_INTERVAL && blooms.length < MAX_BLOOMS) {
			spawnBloom();
			lastBloomTime = time;
		}

		// Update and draw blooms
		for (const bloom of blooms) {
			bloom.update();
			bloom.draw();
		}

		// Remove dead blooms
		blooms = blooms.filter((b) => b.alive);

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Isometric Terrain
 * Description: An isometric grid of diamond-shaped tiles that undulate like rolling
 * hills using sine waves. Height is represented by shade/opacity. Mouse creates a
 * wave disturbance. Uses a subtle monochrome palette.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let lastTime = 0;
let cols, rows;

const TILE_WIDTH = 40;
const TILE_HEIGHT = 20;
const WAVE_AMPLITUDE = 12;
const WAVE_FREQUENCY = 0.08;
const WAVE_SPEED = 0.8;
const MOUSE_WAVE_RADIUS = 250;
const MOUSE_WAVE_AMP = 18;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			recalcGrid();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			recalcGrid();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function recalcGrid() {
	// Extra tiles beyond screen edges to prevent pop-in
	cols = Math.ceil(width / (TILE_WIDTH / 2)) + 4;
	rows = Math.ceil(height / (TILE_HEIGHT / 2)) + 8;
}

/**
 * Convert grid coordinates to isometric screen coordinates.
 * The grid origin is offset so tiles fill the screen.
 */
function gridToIso(gx, gy) {
	const halfW = TILE_WIDTH / 2;
	const halfH = TILE_HEIGHT / 2;
	return {
		x: (gx - gy) * halfW + width / 2,
		y: (gx + gy) * halfH - (rows * halfH) / 2 + height / 2
	};
}

/**
 * Calculate the height offset for a tile at grid position (gx, gy).
 * Combines multiple sine waves for organic terrain, plus mouse disturbance.
 */
function getHeight(gx, gy) {
	// Layered sine waves for natural undulation
	let h = 0;
	h += Math.sin(gx * WAVE_FREQUENCY + time * WAVE_SPEED) * WAVE_AMPLITUDE;
	h += Math.sin(gy * WAVE_FREQUENCY * 1.3 + time * WAVE_SPEED * 0.7) * WAVE_AMPLITUDE * 0.6;
	h += Math.sin((gx + gy) * WAVE_FREQUENCY * 0.5 + time * WAVE_SPEED * 1.2) * WAVE_AMPLITUDE * 0.4;

	// Mouse wave disturbance
	const iso = gridToIso(gx, gy);
	const mouseDist = Math.hypot(iso.x - mouse.x, iso.y - mouse.y);
	if (mouseDist < MOUSE_WAVE_RADIUS) {
		const influence = 1 - mouseDist / MOUSE_WAVE_RADIUS;
		const mouseWave = Math.sin(mouseDist * 0.04 - time * 3) * influence;
		h += mouseWave * MOUSE_WAVE_AMP;
	}

	return h;
}

/** Draw an isometric diamond tile */
function drawTile(cx, cy, heightOffset, brightness) {
	const halfW = TILE_WIDTH / 2;
	const halfH = TILE_HEIGHT / 2;
	const y = cy - heightOffset;

	// Top face of the tile
	ctx.beginPath();
	ctx.moveTo(cx, y - halfH); // top
	ctx.lineTo(cx + halfW, y); // right
	ctx.lineTo(cx, y + halfH); // bottom
	ctx.lineTo(cx - halfW, y); // left
	ctx.closePath();

	// Fill with height-based brightness
	const gray = Math.floor(180 + brightness * 60);
	const alpha = 0.03 + brightness * 0.06;
	ctx.fillStyle = `rgba(${gray}, ${gray}, ${Math.floor(gray * 1.05)}, ${alpha})`;
	ctx.fill();

	// Stroke
	const strokeAlpha = 0.04 + brightness * 0.05;
	ctx.strokeStyle = `rgba(200, 205, 215, ${strokeAlpha})`;
	ctx.lineWidth = 0.6;
	ctx.stroke();
}

function startAnimation() {
	lastTime = performance.now() / 1000;

	function render() {
		if (!ctx) return;

		const now = performance.now() / 1000;
		const dt = Math.min(now - lastTime, 0.05);
		lastTime = now;
		time += dt;

		ctx.clearRect(0, 0, width, height);

		// Track min/max height for normalization
		let minH = Infinity;
		let maxH = -Infinity;

		// Pre-compute heights
		const heights = [];
		for (let gy = 0; gy < rows; gy++) {
			heights[gy] = [];
			for (let gx = 0; gx < cols; gx++) {
				const h = getHeight(gx - cols / 2, gy - rows / 2);
				heights[gy][gx] = h;
				if (h < minH) minH = h;
				if (h > maxH) maxH = h;
			}
		}

		const heightRange = maxH - minH || 1;

		// Draw tiles back to front (painter's algorithm via row order)
		for (let gy = 0; gy < rows; gy++) {
			for (let gx = 0; gx < cols; gx++) {
				const adjustedGx = gx - cols / 2;
				const adjustedGy = gy - rows / 2;
				const iso = gridToIso(adjustedGx, adjustedGy);
				const h = heights[gy][gx];

				// Normalize brightness 0-1
				const brightness = (h - minH) / heightRange;

				// Only draw tiles that are potentially visible
				if (
					iso.x > -TILE_WIDTH &&
					iso.x < width + TILE_WIDTH &&
					iso.y - h > -TILE_HEIGHT * 3 &&
					iso.y - h < height + TILE_HEIGHT * 3
				) {
					drawTile(iso.x, iso.y, h, brightness);
				}
			}
		}

		// Subtle mouse indicator glow
		if (mouse.x > 0 && mouse.y > 0) {
			const gradient = ctx.createRadialGradient(mouse.x, mouse.y, 0, mouse.x, mouse.y, 100);
			gradient.addColorStop(0, 'rgba(200, 210, 230, 0.03)');
			gradient.addColorStop(1, 'rgba(200, 210, 230, 0)');
			ctx.fillStyle = gradient;
			ctx.fillRect(mouse.x - 100, mouse.y - 100, 200, 200);
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Kaleido Spiral Vortex
 * Description: A kaleidoscopic vortex of rotating radial wedges with pulsing
 *   scale wobble and smooth hue cycling. A subtle noise overlay adds texture
 *   across the wedge faces.
 */

// ---------- CONFIGURABLE VARIABLES ----------
const FPS            = 60;          // target frames per second (approx)
const ROTATION_SPEED = 0.01;        // radians per frame
const WEDGES         = 12;          // number of radial wedges
const WAVE_SPEED     = 2;           // speed of the scale “wobble”
const WAVE_AMP       = 0.3;         // amplitude of the scale wobble (0–1)
const HUE_BASE       = 30;          // hue step per wedge
const HUE_SPEED      = 180;         // hue shift per second
const SATURATION     = 100;         // HSL saturation %
const LIGHTNESS      = 55;          // HSL lightness %
const NOISE_MIN      = 0.03;        // minimum overlay opacity
const NOISE_RANGE    = 0.02;        // additional overlay range
// ------------------------------------------

let c, ctx, w, h, angle = 0;

self.onmessage = e => {
  if (e.data.type === 'init') {
    c = e.data.canvas;
    ctx = c.getContext('2d');
    w = c.width = e.data.width;
    h = c.height = e.data.height;
    loop();
  }
  if (e.data.type === 'resize') {
    w = c.width = e.data.width;
    h = c.height = e.data.height;
  }
};

function loop() {
  angle += ROTATION_SPEED;

  // Clear to transparency every frame
  ctx.clearRect(0, 0, w, h);

  // draw radial wedges
  for (let i = 0; i < WEDGES; i++) {
    ctx.save();
    ctx.translate(w / 2, h / 2);
    ctx.rotate((i * 2 * Math.PI) / WEDGES + angle);
    ctx.scale(
      1 + WAVE_AMP * Math.sin(WAVE_SPEED * angle + i),
      1 + WAVE_AMP * Math.cos(WAVE_SPEED * angle + i)
    );
    ctx.beginPath();
    ctx.moveTo(0, 0);
    ctx.arc(0, 0, w, 0, Math.PI / WEDGES);
    ctx.closePath();
    ctx.fillStyle = `hsl(${(i * HUE_BASE + angle * HUE_SPEED) % 360},${SATURATION}%,${LIGHTNESS}%)`;
    ctx.fill();
    ctx.restore();
  }

  // noisy overlay - using source-atop to ensure the noise only affects 
  // the wedges and does not 'fog' the transparent chat background gap
  ctx.globalCompositeOperation = 'source-atop';
  ctx.fillStyle = `rgba(255,255,255,${NOISE_MIN + NOISE_RANGE * Math.abs(Math.sin(angle))})`;
  ctx.fillRect(0, 0, w, h);
  ctx.globalCompositeOperation = 'source-over';

  requestAnimationFrame(loop);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Kaleidoscope
 * Description: Mesmerizing kaleidoscope pattern with mirrored segments and
 *   interactive mouse-driven seed point control.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Symmetry --
  segmentCount: 8,                 // Mirror segments (4, 6, 8, 12)
  rotationSpeed: 0.003,            // Rotation speed in radians/frame (0.001-0.02)
  reflectionEnabled: true,         // Enable reflection within segments

  // -- Source Pattern --
  sourcePattern: 'mixed',          // Pattern type: 'circles', 'lines', 'mixed'
  patternElementCount: 30,         // Number of pattern elements per segment (10-80)
  patternSpeed: 0.008,             // Element animation speed (0.001-0.05)
  elementSizeRange: [4, 28],       // Min/max element size in px
  lineWidth: 1.5,                  // Stroke width for line elements (0.5-4)

  // -- Colors --
  colorPalette: [                  // Colors cycled across elements
    '#ff006e', '#fb5607', '#ffbe0b',
    '#8338ec', '#3a86ff', '#06d6a0',
    '#118ab2', '#ef476f'
  ],
  backgroundColor: 'rgba(0,0,0,0.08)', // Trail fade color (lower alpha = longer trails)

  // -- Geometry --
  centerRadius: 30,                // Blank zone at center in px (0-100)
  outerFade: 0.85,                 // Fade start as fraction of radius (0.5-1.0)

  // -- Mouse Interaction --
  // Mouse position shifts the pattern seed point for the source drawing
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let elements = [];
let cx, cy, maxR;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function initElements() {
  cx = width / 2;
  cy = height / 2;
  maxR = Math.min(cx, cy);
  elements = [];
  for (let i = 0; i < CONFIG.patternElementCount; i++) {
    elements.push(createRandomElement(i));
  }
}

function createRandomElement(index) {
  const types = CONFIG.sourcePattern === 'mixed'
    ? ['circle', 'line']
    : [CONFIG.sourcePattern === 'circles' ? 'circle' : 'line'];
  const type = types[index % types.length];
  const colorIdx = index % CONFIG.colorPalette.length;
  const [minS, maxS] = CONFIG.elementSizeRange;
  return {
    type,
    angle: Math.random() * Math.PI * 2,
    radius: CONFIG.centerRadius + Math.random() * (maxR - CONFIG.centerRadius) * 0.8,
    size: minS + Math.random() * (maxS - minS),
    speed: (0.5 + Math.random()) * CONFIG.patternSpeed,
    radiusSpeed: (Math.random() - 0.5) * CONFIG.patternSpeed * 0.5,
    phase: Math.random() * Math.PI * 2,
    color: CONFIG.colorPalette[colorIdx],
    opacity: 0.4 + Math.random() * 0.6,
  };
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initElements();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initElements();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function parseColor(hex, alpha) {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `rgba(${r},${g},${b},${alpha})`;
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 1;

    // Trail fade
    ctx.fillStyle = CONFIG.backgroundColor;
    ctx.fillRect(0, 0, width, height);

    const segments = CONFIG.segmentCount;
    const sliceAngle = (Math.PI * 2) / segments;
    const rotation = time * CONFIG.rotationSpeed;

    // Mouse-driven seed offset
    let seedX = 0, seedY = 0;
    if (mouse.x > 0 && mouse.y > 0) {
      seedX = (mouse.x - cx) * 0.002;
      seedY = (mouse.y - cy) * 0.002;
    }

    // Update elements
    for (const el of elements) {
      el.angle += el.speed + seedX * 0.05;
      el.radius += el.radiusSpeed;
      el.phase += CONFIG.patternSpeed;

      // Bounce radius
      if (el.radius < CONFIG.centerRadius || el.radius > maxR * 0.85) {
        el.radiusSpeed *= -1;
        el.radius = Math.max(CONFIG.centerRadius, Math.min(maxR * 0.85, el.radius));
      }
    }

    ctx.save();
    ctx.translate(cx, cy);

    for (let s = 0; s < segments; s++) {
      ctx.save();
      ctx.rotate(rotation + s * sliceAngle);

      // Clip to segment
      ctx.beginPath();
      ctx.moveTo(0, 0);
      ctx.arc(0, 0, maxR, 0, sliceAngle);
      ctx.closePath();
      ctx.clip();

      // Draw elements in this segment
      for (const el of elements) {
        const a = el.angle + seedY * 0.1;
        const px = Math.cos(a) * el.radius;
        const py = Math.sin(a) * el.radius;

        // Fade near edges
        const distRatio = el.radius / maxR;
        let fade = 1;
        if (distRatio > CONFIG.outerFade) {
          fade = 1 - (distRatio - CONFIG.outerFade) / (1 - CONFIG.outerFade);
        }

        const alpha = el.opacity * fade;
        if (alpha <= 0) continue;

        ctx.fillStyle = parseColor(el.color, alpha);
        ctx.strokeStyle = parseColor(el.color, alpha * 0.8);
        ctx.lineWidth = CONFIG.lineWidth;

        if (el.type === 'circle') {
          const pulsedSize = el.size * (0.7 + 0.3 * Math.sin(el.phase));
          ctx.beginPath();
          ctx.arc(px, py, pulsedSize, 0, Math.PI * 2);
          ctx.fill();
        } else {
          const len = el.size * 1.5;
          const la = a + Math.sin(el.phase) * 0.5;
          ctx.beginPath();
          ctx.moveTo(px - Math.cos(la) * len, py - Math.sin(la) * len);
          ctx.lineTo(px + Math.cos(la) * len, py + Math.sin(la) * len);
          ctx.stroke();
        }

        // Reflection
        if (CONFIG.reflectionEnabled) {
          const ry = -py;
          ctx.fillStyle = parseColor(el.color, alpha * 0.5);
          ctx.strokeStyle = parseColor(el.color, alpha * 0.4);
          if (el.type === 'circle') {
            const pulsedSize = el.size * (0.7 + 0.3 * Math.sin(el.phase));
            ctx.beginPath();
            ctx.arc(px, ry, pulsedSize, 0, Math.PI * 2);
            ctx.fill();
          } else {
            const len = el.size * 1.5;
            const la = -a + Math.sin(el.phase) * 0.5;
            ctx.beginPath();
            ctx.moveTo(px - Math.cos(la) * len, ry - Math.sin(la) * len);
            ctx.lineTo(px + Math.cos(la) * len, ry + Math.sin(la) * len);
            ctx.stroke();
          }
        }
      }

      ctx.restore();
    }

    // Center mask
    if (CONFIG.centerRadius > 0) {
      const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, CONFIG.centerRadius);
      grad.addColorStop(0, 'rgba(0,0,0,0.9)');
      grad.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(0, 0, CONFIG.centerRadius, 0, Math.PI * 2);
      ctx.fill();
    }

    ctx.restore();
    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Lava Lamp
 * Description: Large, soft, amorphous blobs that slowly rise, merge, split,
 *   and sink like a lava lamp. Warm colors (deep reds, oranges, magentas)
 *   with very low opacity and heavy blur. Mouse attracts nearby blobs.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let blobs = [];
let time = 0;

const BLOB_COUNT = 12;
const MOUSE_ATTRACT_RADIUS = 250;
const MOUSE_ATTRACT_STRENGTH = 0.4;

// Heartbeat to keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// Warm color palette: deep reds, oranges, magentas
const COLORS = [
	{ r: 180, g: 30, b: 20 }, // deep red
	{ r: 200, g: 60, b: 10 }, // burnt orange
	{ r: 160, g: 20, b: 80 }, // magenta
	{ r: 220, g: 80, b: 20 }, // orange
	{ r: 140, g: 10, b: 50 }, // dark crimson
	{ r: 190, g: 40, b: 60 } // rose red
];

class Blob {
	constructor() {
		this.reset();
	}

	reset() {
		this.x = Math.random() * width;
		this.y = Math.random() * height;
		this.radius = 60 + Math.random() * 100;
		this.baseRadius = this.radius;
		this.vx = (Math.random() - 0.5) * 0.3;
		this.vy = -0.2 - Math.random() * 0.5; // drift upward
		this.color = COLORS[Math.floor(Math.random() * COLORS.length)];
		this.phase = Math.random() * Math.PI * 2;
		this.pulseSpeed = 0.005 + Math.random() * 0.01;
		this.wobbleAmpX = 0.3 + Math.random() * 0.5;
		this.wobbleAmpY = 0.2 + Math.random() * 0.3;
		this.wobbleFreqX = 0.008 + Math.random() * 0.006;
		this.wobbleFreqY = 0.006 + Math.random() * 0.008;
		this.alpha = 0.04 + Math.random() * 0.06;
	}

	update() {
		// Slow organic drift
		this.x += this.vx + Math.sin(time * this.wobbleFreqX + this.phase) * this.wobbleAmpX;
		this.y += this.vy + Math.cos(time * this.wobbleFreqY + this.phase) * this.wobbleAmpY;

		// Pulsing radius
		this.radius = this.baseRadius + Math.sin(time * this.pulseSpeed + this.phase) * 20;

		// Mouse attraction
		const dx = mouse.x - this.x;
		const dy = mouse.y - this.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		if (dist < MOUSE_ATTRACT_RADIUS && dist > 1) {
			const force = (1 - dist / MOUSE_ATTRACT_RADIUS) * MOUSE_ATTRACT_STRENGTH;
			this.x += (dx / dist) * force;
			this.y += (dy / dist) * force;
		}

		// Wrap around vertically — blobs that rise off top reappear at bottom
		if (this.y + this.radius < -50) {
			this.y = height + this.radius + 50;
			this.x = Math.random() * width;
		}
		// Occasionally sink back down (some blobs drift downward)
		if (this.y - this.radius > height + 100) {
			this.y = -this.radius - 50;
			this.x = Math.random() * width;
		}

		// Soft horizontal bounds
		if (this.x < -this.radius * 2) this.x = width + this.radius;
		if (this.x > width + this.radius * 2) this.x = -this.radius;
	}

	draw() {
		const { r, g, b } = this.color;

		// Draw multiple layered radial gradients for a soft, blurred look
		for (let layer = 0; layer < 3; layer++) {
			const layerScale = 1 + layer * 0.4;
			const layerAlpha = this.alpha / (layer + 1);
			const rad = this.radius * layerScale;

			const gradient = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, rad);
			gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${layerAlpha})`);
			gradient.addColorStop(0.4, `rgba(${r}, ${g}, ${b}, ${layerAlpha * 0.6})`);
			gradient.addColorStop(0.7, `rgba(${r}, ${g}, ${b}, ${layerAlpha * 0.2})`);
			gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);

			ctx.beginPath();
			ctx.arc(this.x, this.y, rad, 0, Math.PI * 2);
			ctx.fillStyle = gradient;
			ctx.fill();
		}
	}
}

function initBlobs() {
	blobs = [];
	for (let i = 0; i < BLOB_COUNT; i++) {
		blobs.push(new Blob());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initBlobs();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initBlobs();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;

		// Soft fade instead of full clear for trailing effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.08)';
		ctx.fillRect(0, 0, width, height);

		time++;

		// Update and draw blobs
		for (const blob of blobs) {
			blob.update();
		}
		for (const blob of blobs) {
			blob.draw();
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Lightning
 * Description: Dramatic lightning bolts that fork and flash against a dark sky.
 *   Mouse click area triggers a targeted bolt. Background flashes and rumble glow
 *   create an immersive storm atmosphere.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Bolt Appearance --
  boltColor: 'rgba(180, 200, 255, 0.95)',   // Main bolt stroke color
  boltWidth: 2.5,                            // Base stroke width of the main bolt in px
  boltSegments: 12,                          // Number of jagged segments per bolt
  boltJagOffset: 35,                         // Max horizontal offset per segment in px
  boltGlowColor: 'rgba(140, 170, 255, 0.5)',// Glow halo around bolts
  boltGlowWidth: 10,                         // Glow blur radius in px

  // -- Forking --
  forkProbability: 0.35,                     // Chance each segment spawns a fork (0-1)
  maxForkDepth: 3,                           // Maximum recursive fork depth
  forkLengthFactor: 0.55,                    // Fork length relative to remaining bolt (0-1)
  forkWidthDecay: 0.6,                       // Stroke width multiplier per fork depth

  // -- Flash --
  flashBrightness: 0.35,                     // Peak screen-flash opacity (0-1)
  flashDuration: 350,                        // Flash fade-out duration in ms
  backgroundFlashColor: 'rgba(200, 215, 255, 1)', // Color of the full-screen flash

  // -- Timing --
  boltFrequency: 2200,                       // Average ms between auto bolts
  boltFrequencyVariance: 1500,               // ± random ms added to frequency
  boltLifetime: 180,                         // How long a bolt stays visible in ms

  // -- Rumble --
  rumbleGlowColor: 'rgba(100, 120, 180, 0.08)', // Subtle ambient storm glow at horizon
  rumbleGlowHeight: 0.25,                       // Fraction of canvas height for rumble glow

  // -- Mouse Interaction --
  mouseClickBolt: true,                      // Whether mouse area triggers targeted bolts
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let bolts = [];
let flashAlpha = 0;
let flashStart = 0;
let lastBoltTime = 0;
let nextBoltDelay = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      nextBoltDelay = CONFIG.boltFrequency;
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
    case 'mousedown':
    case 'click':
      if (CONFIG.mouseClickBolt) {
        spawnBolt(e.data.x || mouse.x, 0, e.data.x || mouse.x, e.data.y || mouse.y);
      }
      break;
  }
};

function generateBoltPath(x1, y1, x2, y2, segments, depth) {
  const points = [{ x: x1, y: y1 }];
  const dx = x2 - x1;
  const dy = y2 - y1;

  for (let i = 1; i < segments; i++) {
    const t = i / segments;
    const px = x1 + dx * t + (Math.random() - 0.5) * CONFIG.boltJagOffset * 2;
    const py = y1 + dy * t + (Math.random() - 0.5) * CONFIG.boltJagOffset * 0.5;
    points.push({ x: px, y: py });
  }
  points.push({ x: x2, y: y2 });

  // Generate forks
  const forks = [];
  if (depth < CONFIG.maxForkDepth) {
    for (let i = 2; i < points.length - 1; i++) {
      if (Math.random() < CONFIG.forkProbability) {
        const p = points[i];
        const remainLen = Math.sqrt(
          (x2 - p.x) ** 2 + (y2 - p.y) ** 2
        ) * CONFIG.forkLengthFactor;
        const angle = Math.atan2(y2 - y1, x2 - x1) + (Math.random() - 0.5) * 1.2;
        const fx = p.x + Math.cos(angle) * remainLen;
        const fy = p.y + Math.sin(angle) * remainLen;
        const forkSegs = Math.max(3, Math.floor(segments * 0.5));
        forks.push(generateBoltPath(p.x, p.y, fx, fy, forkSegs, depth + 1));
      }
    }
  }

  return { points, forks, depth };
}

function spawnBolt(x1, y1, x2, y2) {
  const path = generateBoltPath(
    x1 || Math.random() * width, y1 || 0,
    x2 || (x1 + (Math.random() - 0.5) * width * 0.4),
    y2 || height * (0.5 + Math.random() * 0.5),
    CONFIG.boltSegments, 0
  );
  bolts.push({ path, born: performance.now() });

  // Trigger flash
  flashAlpha = CONFIG.flashBrightness;
  flashStart = performance.now();
}

function drawBoltPath(boltPath, alpha) {
  const w = CONFIG.boltWidth * Math.pow(CONFIG.forkWidthDecay, boltPath.depth);

  // Glow
  ctx.save();
  ctx.strokeStyle = CONFIG.boltGlowColor;
  ctx.lineWidth = w + CONFIG.boltGlowWidth;
  ctx.globalAlpha = alpha * 0.5;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  ctx.beginPath();
  ctx.moveTo(boltPath.points[0].x, boltPath.points[0].y);
  for (let i = 1; i < boltPath.points.length; i++) {
    ctx.lineTo(boltPath.points[i].x, boltPath.points[i].y);
  }
  ctx.stroke();
  ctx.restore();

  // Core
  ctx.save();
  ctx.strokeStyle = CONFIG.boltColor;
  ctx.lineWidth = w;
  ctx.globalAlpha = alpha;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  ctx.beginPath();
  ctx.moveTo(boltPath.points[0].x, boltPath.points[0].y);
  for (let i = 1; i < boltPath.points.length; i++) {
    ctx.lineTo(boltPath.points[i].x, boltPath.points[i].y);
  }
  ctx.stroke();
  ctx.restore();

  // Inner bright core
  ctx.save();
  ctx.strokeStyle = 'rgba(255, 255, 255, 0.9)';
  ctx.lineWidth = Math.max(1, w * 0.35);
  ctx.globalAlpha = alpha * 0.8;
  ctx.lineCap = 'round';
  ctx.beginPath();
  ctx.moveTo(boltPath.points[0].x, boltPath.points[0].y);
  for (let i = 1; i < boltPath.points.length; i++) {
    ctx.lineTo(boltPath.points[i].x, boltPath.points[i].y);
  }
  ctx.stroke();
  ctx.restore();

  // Draw forks recursively
  for (const fork of boltPath.forks) {
    drawBoltPath(fork, alpha * 0.75);
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    const now = performance.now();

    ctx.clearRect(0, 0, width, height);

    // Rumble glow at bottom
    const rumbleGrad = ctx.createLinearGradient(0, height * (1 - CONFIG.rumbleGlowHeight), 0, height);
    rumbleGrad.addColorStop(0, 'transparent');
    rumbleGrad.addColorStop(1, CONFIG.rumbleGlowColor);
    ctx.fillStyle = rumbleGrad;
    ctx.fillRect(0, height * (1 - CONFIG.rumbleGlowHeight), width, height * CONFIG.rumbleGlowHeight);

    // Auto-spawn bolts
    if (now - lastBoltTime > nextBoltDelay) {
      const startX = Math.random() * width;
      spawnBolt(startX, 0, startX + (Math.random() - 0.5) * width * 0.3, height * (0.4 + Math.random() * 0.6));
      lastBoltTime = now;
      nextBoltDelay = CONFIG.boltFrequency + (Math.random() - 0.5) * 2 * CONFIG.boltFrequencyVariance;
    }

    // Draw active bolts
    for (let i = bolts.length - 1; i >= 0; i--) {
      const b = bolts[i];
      const age = now - b.born;
      if (age > CONFIG.boltLifetime) {
        bolts.splice(i, 1);
        continue;
      }
      const alpha = 1 - age / CONFIG.boltLifetime;
      drawBoltPath(b.path, alpha);
    }

    // Screen flash overlay
    if (flashAlpha > 0.001) {
      const elapsed = now - flashStart;
      const currentFlash = flashAlpha * Math.max(0, 1 - elapsed / CONFIG.flashDuration);
      if (currentFlash > 0.001) {
        ctx.save();
        ctx.globalAlpha = currentFlash;
        ctx.fillStyle = CONFIG.backgroundFlashColor;
        ctx.fillRect(0, 0, width, height);
        ctx.restore();
      } else {
        flashAlpha = 0;
      }
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Liquid Chrome (WebGL)
 * Description: A flowing metallic liquid surface rendered with GPU shaders.
 *   Multiple layers of warped noise create a convincing reflective chrome
 *   membrane that ripples and morphs organically. Mouse interaction creates
 *   a deep gravity well that pulls the liquid surface toward the cursor,
 *   revealing iridescent prismatic reflections underneath.
 *
 *   Showcases: WebGL shaders, metallic rendering, mousemove
 */

/* ────────── CONFIGURABLE ────────── */
var SPEED           = 0.15;     // flow speed
var SCALE           = 1.8;      // noise zoom level (lower = bigger features)
var WARP_DEPTH      = 3;        // domain warp passes (1-4, higher = more complex)
var REFLECTIVITY    = 0.7;      // chrome reflection intensity
var IRIDESCENCE     = 0.5;      // rainbow refraction amount
var MOUSE_PULL      = 0.25;     // mouse gravity well strength
var MOUSE_RADIUS    = 0.3;      // mouse influence radius
var EDGE_LIGHT      = 1.3;      // rim/edge lighting intensity
/* ──────────────────────────────────── */

var canvas, gl, program;
var uTime, uRes, uMouse, uCfg;
var startTime = 0;
var mouseNX = 0.5, mouseNY = 0.5;
var w = 0, h = 0;

setInterval(function() { self.postMessage({ type: 'heartbeat' }); }, 1000);

var VERT = 'attribute vec2 a_pos;void main(){gl_Position=vec4(a_pos,0,1);}';

var FRAG = [
'precision highp float;',
'uniform float u_time;',
'uniform vec2 u_res;',
'uniform vec2 u_mouse;',
'uniform vec4 u_cfg;', // reflectivity, iridescence, mousePull, edgeLight
'',
'// ── Noise foundation ──',
'vec3 mod289(vec3 x){return x-floor(x*(1./289.))*289.;}',
'vec4 mod289(vec4 x){return x-floor(x*(1./289.))*289.;}',
'vec4 perm(vec4 x){return mod289(((x*34.)+1.)*x);}',
'',
'float snoise(vec3 v){',
'  vec3 C=vec3(1./6.,1./3.,0.);',
'  vec3 i=floor(v+dot(v,C.yyy));',
'  vec3 x0=v-i+dot(i,C.xxx);',
'  vec3 g=step(x0.yzx,x0.xyz);',
'  vec3 l=1.-g;',
'  vec3 i1=min(g,l.zxy);',
'  vec3 i2=max(g,l.zxy);',
'  vec3 x1=x0-i1+C.x;',
'  vec3 x2=x0-i2+C.y;',
'  vec3 x3=x0-.5;',
'  i=mod289(i);',
'  vec4 p=perm(perm(perm(',
'    i.z+vec4(0,i1.z,i2.z,1))',
'    +i.y+vec4(0,i1.y,i2.y,1))',
'    +i.x+vec4(0,i1.x,i2.x,1));',
'  vec4 j=p-49.*floor(p*(1./49.));',
'  vec4 x_=floor(j*(1./7.));',
'  vec4 y_=floor(j-7.*x_);',
'  vec4 ox=(x_*2.+.5)/7.-1.;',
'  vec4 oy=(y_*2.+.5)/7.-1.;',
'  vec4 dg=vec4(dot(vec3(ox.x,oy.x,0),x0),dot(vec3(ox.y,oy.y,0),x1),',
'               dot(vec3(ox.z,oy.z,0),x2),dot(vec3(ox.w,oy.w,0),x3));',
'  vec4 m=max(.6-vec4(dot(x0,x0),dot(x1,x1),dot(x2,x2),dot(x3,x3)),0.);',
'  m=m*m;',
'  return 42.*dot(m*m,dg);',
'}',
'',
'float fbm(vec3 p){',
'  float f=0.,a=.5;',
'  for(int i=0;i<6;i++){f+=a*snoise(p);p*=2.02;a*=.48;}',
'  return f;',
'}',
'',
'// ── Iridescent palette ──',
'vec3 iridescent(float t,float iri){',
'  vec3 a=vec3(.5);vec3 b=vec3(.5);',
'  vec3 c=vec3(1.);vec3 d=vec3(.0,.33,.67);',
'  vec3 base=a+b*cos(6.28318*(c*t+d));',
'  return mix(vec3(dot(base,vec3(.299,.587,.114))),base,iri);',
'}',
'',
'// ── Chrome reflection model ──',
'vec3 chromeReflect(vec2 p,float t,float nDot,float refl){',
'  // Fake environment map — gradient sky + ground',
'  float envY=nDot*.8+.1;',
'  vec3 sky=mix(vec3(.05,.05,.12),vec3(.2,.25,.35),smoothstep(0.,.8,envY));',
'  vec3 ground=mix(vec3(.08,.06,.05),vec3(.15,.12,.1),smoothstep(-.5,0.,envY));',
'  vec3 env=mix(ground,sky,smoothstep(-.1,.1,envY));',
'  // Bright highlights',
'  float highlight=pow(max(nDot,0.),12.)*.8;',
'  env+=vec3(highlight);',
'  return env*refl;',
'}',
'',
'void main(){',
'  vec2 uv=(2.*gl_FragCoord.xy-u_res)/min(u_res.x,u_res.y);',
'  float t=u_time;',
'  float refl=u_cfg.x;',
'  float iri=u_cfg.y;',
'  float mPull=u_cfg.z;',
'  float eLit=u_cfg.w;',
'',
'  // ── Mouse gravity well ──',
'  vec2 mp=(2.*u_mouse*u_res-u_res)/min(u_res.x,u_res.y);',
'  float md=length(uv-mp);',
'  float mInfl=mPull/(1.+md*md/('+MOUSE_RADIUS.toFixed(2)+'*'+MOUSE_RADIUS.toFixed(2)+'));',
'  vec2 p=uv+(mp-uv)*mInfl;',
'',
'  // ── Multi-pass domain warping for organic flow ──',
'  vec3 q=vec3(p*' + SCALE.toFixed(1) + ',t);',
'  float n1=fbm(q);',
'  float n2=fbm(q+vec3(n1*1.4,n1*0.9,0.3));',
'  float n3=fbm(q+vec3(n2*1.2,-n2*1.1,n1*0.5+t*0.15));',
'',
'  // ── Surface normal estimation (for lighting) ──',
'  float eps=0.008;',
'  float nR=fbm(vec3((p.x+eps)*' + SCALE.toFixed(1) + ',p.y*' + SCALE.toFixed(1) + ',t)',
'           +vec3(n2*1.2,-n2*1.1,n1*0.5+t*0.15));',
'  float nU=fbm(vec3(p.x*' + SCALE.toFixed(1) + ',(p.y+eps)*' + SCALE.toFixed(1) + ',t)',
'           +vec3(n2*1.2,-n2*1.1,n1*0.5+t*0.15));',
'  vec3 normal=normalize(vec3((n3-nR)/eps,(n3-nU)/eps,1.));',
'',
'  // ── Lighting ──',
'  vec3 lightDir=normalize(vec3(0.4,0.6,1.0));',
'  float nDot=dot(normal,lightDir);',
'  float diffuse=max(nDot,0.)*0.3;',
'',
'  // Specular',
'  vec3 viewDir=vec3(0.,0.,1.);',
'  vec3 halfDir=normalize(lightDir+viewDir);',
'  float spec=pow(max(dot(normal,halfDir),0.),64.)*1.2;',
'',
'  // Rim/edge lighting',
'  float rim=pow(1.-max(dot(normal,viewDir),0.),3.)*eLit;',
'',
'  // ── Color composition ──',
'  // Base chrome reflection',
'  vec3 chrome=chromeReflect(p,t,nDot,refl);',
'',
'  // Iridescent layer — prismatic refraction from surface curvature',
'  float curvature=n3*0.5+0.5;',
'  vec3 prism=iridescent(curvature+t*0.05,iri);',
'',
'  // Combine',
'  vec3 col=chrome+prism*0.35;',
'  col+=vec3(spec)*vec3(1.,0.97,0.9);',
'  col+=vec3(rim)*mix(vec3(0.2,0.25,0.4),prism*0.4,iri);',
'  col+=diffuse*vec3(0.1,0.1,0.15);',
'',
'  // Depth — subtle darkening of valleys',
'  float depth=smoothstep(-0.3,0.5,n3);',
'  col*=0.6+depth*0.5;',
'',
'  // ── Mouse proximity glow ──',
'  float mouseGlow=exp(-md*md*4.)*0.15;',
'  col+=prism*mouseGlow;',
'',
'  // ── Vignette ──',
'  vec2 vUV=gl_FragCoord.xy/u_res;',
'  float vig=1.-dot(vUV-.5,vUV-.5)*1.3;',
'  col*=max(vig,0.);',
'',
'  gl_FragColor=vec4(col,1.);',
'}'
].join('\n');

/* ── GL setup ── */
function compile(type, src) {
    var s = gl.createShader(type);
    gl.shaderSource(s, src);
    gl.compileShader(s);
    if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) {
        throw new Error(gl.getShaderInfoLog(s));
    }
    return s;
}

function initGL() {
    var vs = compile(gl.VERTEX_SHADER, VERT);
    var fs = compile(gl.FRAGMENT_SHADER, FRAG);
    program = gl.createProgram();
    gl.attachShader(program, vs);
    gl.attachShader(program, fs);
    gl.linkProgram(program);
    if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
        throw new Error(gl.getProgramInfoLog(program));
    }
    gl.useProgram(program);

    var buf = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, buf);
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1,-1, 3,-1, -1,3]), gl.STATIC_DRAW);
    var a = gl.getAttribLocation(program, 'a_pos');
    gl.enableVertexAttribArray(a);
    gl.vertexAttribPointer(a, 2, gl.FLOAT, false, 0, 0);

    uTime = gl.getUniformLocation(program, 'u_time');
    uRes = gl.getUniformLocation(program, 'u_res');
    uMouse = gl.getUniformLocation(program, 'u_mouse');
    uCfg = gl.getUniformLocation(program, 'u_cfg');
    startTime = performance.now() / 1000;
}

function render() {
    var t = (performance.now() / 1000 - startTime) * SPEED;
    gl.viewport(0, 0, w, h);
    gl.uniform1f(uTime, t);
    gl.uniform2f(uRes, w, h);
    gl.uniform2f(uMouse, mouseNX, mouseNY);
    gl.uniform4f(uCfg, REFLECTIVITY, IRIDESCENCE, MOUSE_PULL, EDGE_LIGHT);
    gl.drawArrays(gl.TRIANGLES, 0, 3);
    requestAnimationFrame(render);
}

self.onmessage = function(e) {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            w = e.data.width; h = e.data.height;
            canvas.width = w; canvas.height = h;
            gl = canvas.getContext('webgl2') || canvas.getContext('webgl');
            if (!gl) {
                var c = canvas.getContext('2d');
                c.fillStyle = '#0a0a1a'; c.fillRect(0,0,w,h);
                c.fillStyle = '#ff4466'; c.font = '16px monospace';
                c.textAlign = 'center';
                c.fillText('WebGL not available', w/2, h/2);
                return;
            }
            try { initGL(); render(); }
            catch(err) {
                var c = canvas.getContext('2d');
                if(c){c.fillStyle='#0a0a1a';c.fillRect(0,0,w,h);
                c.fillStyle='#ff4466';c.font='12px monospace';c.textAlign='center';
                c.fillText('Shader: '+err.message,w/2,h/2);}
            }
            break;
        case 'resize':
            w = e.data.width; h = e.data.height;
            canvas.width = w; canvas.height = h;
            break;
        case 'mousemove':
            mouseNX = e.data.x / w;
            mouseNY = 1.0 - (e.data.y / h);
            break;
    }
};

/**
 * Title: Liquid Metal
 * Description: A sinuous, mouse-reactive liquid metal surface. Points follow the
 *   cursor in a smooth chain, generating an undulating wave with a chrome-like
 *   linear gradient fill.
 */
// =========================================================================
// Configurable Parameters
// =========================================================================
const CFG = {
  // Visuals
  GRADIENT_TOP: '#fff',           // top of fill gradient
  GRADIENT_MID: '#888',           // mid-point of fill gradient
  GRADIENT_BOTTOM: '#000',        // bottom of fill gradient
  POINT_COUNT: 24,                // number of points (np)
  POINT_MIN_R: 20,                // min random radius (unused in logic, kept for compatibility)
  POINT_MAX_R: 60,                // max random radius (unused in logic, kept for compatibility)
  SMOOTHING: 0.08,                 // lerp factor for point movement
  WAVE_AMPLITUDE: 20,              // sin wave height offset
  WAVE_FREQ: 0.5,                  // sin wave frequency per point
  TIME_SPEED: 0.01,                // delta-t per frame
};

// =========================================================================
// Worker
// =========================================================================
let c, ctx, w, h, t = 0, rid = 0, pts = [];

function rand(a, b) { return a + (b - a) * Math.random(); }

onmessage = e => {
  if (e.data.type === 'init') {
    c = e.data.canvas;
    ctx = c.getContext('2d');
    w = c.width = e.data.width;
    h = c.height = e.data.height;
    for (let i = 0; i < CFG.POINT_COUNT; i++) {
      pts.push({ x: rand(0, w), y: rand(0, h), r: rand(CFG.POINT_MIN_R, CFG.POINT_MAX_R) });
    }
    draw();
  }
  if (e.data.type === 'resize') {
    w = c.width = e.data.width;
    h = c.height = e.data.height;
  }
  if (e.data.type === 'mousemove') {
    pts[0].x = e.data.x;
    pts[0].y = e.data.y;
  }
};

function draw() {
  rid = requestAnimationFrame(draw);
  t += CFG.TIME_SPEED;

  // Clear the canvas to transparency instead of filling with a solid color
  ctx.clearRect(0, 0, w, h);

  // Smooth follow
  for (let i = 1; i < CFG.POINT_COUNT; i++) {
    let p = pts[i], prev = pts[i - 1];
    p.x += (prev.x - p.x) * CFG.SMOOTHING;
    p.y += (prev.y - p.y) * CFG.SMOOTHING;
  }

  // Draw filled wave
  ctx.beginPath();
  ctx.moveTo(0, h);
  for (let i = 0; i < CFG.POINT_COUNT; i++) {
    let p = pts[i], y = p.y + Math.sin(t + i * CFG.WAVE_FREQ) * CFG.WAVE_AMPLITUDE;
    ctx.lineTo(p.x, y);
  }
  ctx.lineTo(w, h);
  ctx.closePath();

  let g = ctx.createLinearGradient(0, 0, 0, h);
  g.addColorStop(0, CFG.GRADIENT_TOP);
  g.addColorStop(0.5, CFG.GRADIENT_MID);
  g.addColorStop(1, CFG.GRADIENT_BOTTOM);
  ctx.fillStyle = g;
  ctx.fill();
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Living Sky
 * Description: A procedural time-aware landscape that reflects the actual
 *   time of day. Dawn paints the sky pink, midday goes bright blue, dusk
 *   fades to amber, and night reveals stars with occasional shooting stars.
 *   A silhouetted mountain range spans the bottom, clouds drift across, and
 *   the sun/moon arcs overhead tracking real local time. Always different,
 *   always beautiful — no interaction required.
 *
 *   Uses native Date access in the Worker — fully autonomous.
 */

/* ────────── CONFIGURABLE VARIABLES ────────── */
const CLOUD_COUNT         = 8;        // number of drifting clouds
const CLOUD_SPEED         = 0.15;     // cloud drift speed
const STAR_COUNT          = 200;      // stars visible at night
const SHOOTING_STAR_CHANCE = 0.002;   // per-frame chance of a shooting star
const MOUNTAIN_LAYERS     = 3;        // parallax mountain layers
const TERRAIN_HEIGHT      = 0.3;      // terrain height as fraction of viewport
const SUN_MOON_RADIUS     = 18;       // radius of sun/moon circle
const SHOW_TIME_LABEL     = true;     // subtle time display in corner
const TIME_LABEL_FONT     = '500 11px "Inter", system-ui, sans-serif';
/* ──────────────────────────────────────────── */

let canvas, ctx, w, h;
let stars = [];
let clouds = [];
let mountains = []; // array of arrays of points per layer
let shootingStars = [];

const TAU = Math.PI * 2;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

// ── Sky color palette by time ──
// Each entry: [hour, topR, topG, topB, botR, botG, botB]
const SKY_STOPS = [
	[0,   8,  10,  28,  12,  15,  35],   // midnight
	[4,   8,  10,  28,  15,  18,  40],   // pre-dawn
	[5.5, 25,  20,  50,  80,  50,  70],  // early dawn
	[6.5, 60,  80, 140, 220, 140, 100],  // dawn
	[7.5, 80, 140, 210, 250, 190, 130],  // sunrise
	[9,  100, 170, 240, 180, 210, 240],  // morning
	[12, 80,  150, 230, 160, 200, 240],  // noon
	[16, 90,  155, 225, 170, 200, 235],  // afternoon
	[18, 100, 120, 180, 240, 160, 100],  // pre-sunset
	[19, 60,   60, 120, 230, 110,  70],  // sunset
	[20, 30,   30,  80, 120,  60,  60],  // dusk
	[21, 12,   15,  45,  25,  20,  50],  // twilight
	[24,  8,   10,  28,  12,  15,  35],  // midnight wrap
];

function lerpColor(stops, hour) {
	let a = stops[0], b = stops[stops.length - 1];
	for (let i = 0; i < stops.length - 1; i++) {
		if (hour >= stops[i][0] && hour < stops[i + 1][0]) {
			a = stops[i];
			b = stops[i + 1];
			break;
		}
	}
	const t = (hour - a[0]) / (b[0] - a[0] || 1);
	const lerp = (x, y) => Math.round(x + (y - x) * t);
	return {
		topR: lerp(a[1], b[1]), topG: lerp(a[2], b[2]), topB: lerp(a[3], b[3]),
		botR: lerp(a[4], b[4]), botG: lerp(a[5], b[5]), botB: lerp(a[6], b[6])
	};
}

// ── Stars ──
function initStars() {
	stars = [];
	for (let i = 0; i < STAR_COUNT; i++) {
		stars.push({
			x: Math.random() * w,
			y: Math.random() * h * 0.7,
			r: Math.random() * 1.2 + 0.3,
			twinkleSpeed: Math.random() * 2 + 1,
			twinkleOffset: Math.random() * TAU
		});
	}
}

function drawStars(alpha, time) {
	if (alpha <= 0) return;
	ctx.fillStyle = 'white';
	for (let i = 0; i < stars.length; i++) {
		const s = stars[i];
		const twinkle = 0.5 + 0.5 * Math.sin(time * s.twinkleSpeed + s.twinkleOffset);
		ctx.globalAlpha = alpha * twinkle * 0.8;
		ctx.beginPath();
		ctx.arc(s.x, s.y, s.r, 0, TAU);
		ctx.fill();
	}
}

// ── Shooting stars ──
function spawnShootingStar() {
	shootingStars.push({
		x: Math.random() * w * 0.8 + w * 0.1,
		y: Math.random() * h * 0.3,
		vx: (Math.random() * 4 + 3) * (Math.random() > 0.5 ? 1 : -1),
		vy: Math.random() * 2 + 1.5,
		life: 1,
		decay: Math.random() * 0.02 + 0.015,
		length: Math.random() * 40 + 20
	});
}

function updateAndDrawShootingStars(nightAlpha) {
	if (nightAlpha <= 0) return;
	ctx.lineCap = 'round';
	for (let i = shootingStars.length - 1; i >= 0; i--) {
		const s = shootingStars[i];
		s.x += s.vx;
		s.y += s.vy;
		s.life -= s.decay;
		if (s.life <= 0) { shootingStars.splice(i, 1); continue; }
		ctx.globalAlpha = nightAlpha * s.life * 0.7;
		ctx.strokeStyle = 'white';
		ctx.lineWidth = 1.5;
		ctx.beginPath();
		ctx.moveTo(s.x, s.y);
		ctx.lineTo(s.x - s.vx * s.length / 5, s.y - s.vy * s.length / 5);
		ctx.stroke();
	}
}

// ── Clouds ──
function initClouds() {
	clouds = [];
	for (let i = 0; i < CLOUD_COUNT; i++) {
		clouds.push(makeCloud(Math.random() * (w + 400) - 200));
	}
}

function makeCloud(startX) {
	return {
		x: startX,
		y: Math.random() * h * 0.35 + h * 0.05,
		width: Math.random() * 180 + 80,
		height: Math.random() * 30 + 15,
		speed: (Math.random() * 0.5 + 0.2) * CLOUD_SPEED,
		opacity: Math.random() * 0.3 + 0.1,
		puffs: (() => {
			const n = Math.floor(Math.random() * 4) + 3;
			const arr = [];
			for (let j = 0; j < n; j++) {
				arr.push({
					ox: (Math.random() - 0.5) * 0.8,
					oy: (Math.random() - 0.5) * 0.5,
					r: Math.random() * 0.4 + 0.3
				});
			}
			return arr;
		})()
	};
}

function drawClouds(brightness) {
	for (let i = 0; i < clouds.length; i++) {
		const c = clouds[i];
		c.x += c.speed;
		if (c.x > w + c.width) { c.x = -c.width - 50; c.y = Math.random() * h * 0.35 + h * 0.05; }

		const lum = Math.round(200 * brightness + 55);
		ctx.fillStyle = `rgb(${lum}, ${lum}, ${lum})`;

		for (let j = 0; j < c.puffs.length; j++) {
			const p = c.puffs[j];
			ctx.globalAlpha = c.opacity * brightness;
			ctx.beginPath();
			ctx.ellipse(
				c.x + p.ox * c.width,
				c.y + p.oy * c.height,
				c.width * p.r * 0.5,
				c.height * p.r,
				0, 0, TAU
			);
			ctx.fill();
		}
	}
}

// ── Mountains ──
function initMountains() {
	mountains = [];
	for (let layer = 0; layer < MOUNTAIN_LAYERS; layer++) {
		const pts = [];
		const segments = 20 + layer * 5;
		const baseY = h - (h * TERRAIN_HEIGHT) * (1 - layer / MOUNTAIN_LAYERS * 0.6);
		const amplitude = h * TERRAIN_HEIGHT * (0.5 - layer * 0.12);

		pts.push({ x: -10, y: h + 10 });
		for (let i = 0; i <= segments; i++) {
			const x = (i / segments) * (w + 20) - 10;
			const noise = Math.sin(i * 0.8 + layer * 3) * 0.5
				+ Math.sin(i * 1.7 + layer * 7) * 0.3
				+ Math.sin(i * 3.1 + layer * 11) * 0.2;
			const y = baseY - amplitude * (noise * 0.5 + 0.5);
			pts.push({ x, y });
		}
		pts.push({ x: w + 10, y: h + 10 });

		mountains.push(pts);
	}
}

function drawMountains(skyColor) {
	for (let layer = 0; layer < mountains.length; layer++) {
		const pts = mountains[layer];
		const darkness = 0.3 + layer * 0.25;
		const r = Math.round(skyColor.botR * (1 - darkness));
		const g = Math.round(skyColor.botG * (1 - darkness));
		const b = Math.round(skyColor.botB * (1 - darkness));
		ctx.globalAlpha = 1;
		ctx.fillStyle = `rgb(${r}, ${g}, ${b})`;
		ctx.beginPath();
		ctx.moveTo(pts[0].x, pts[0].y);
		for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
		ctx.closePath();
		ctx.fill();
	}
}

// ── Sun / Moon ──
function drawCelestialBody(hour, skyColor) {
	// Sun visible ~6am–7pm, Moon visible ~7pm–6am
	const sunAngle = ((hour - 6) / 13) * Math.PI; // 6am=0, 7pm=π
	const moonAngle = ((hour < 7 ? hour + 24 : hour) - 19) / 11 * Math.PI; // 7pm=0, 6am=π

	const horizonY = h * (1 - TERRAIN_HEIGHT * 0.6);

	// Sun
	if (hour >= 5.5 && hour <= 19.5) {
		const t = Math.max(0, Math.min(1, (hour - 5.5) / 1)); // fade in
		const t2 = Math.max(0, Math.min(1, (19.5 - hour) / 1)); // fade out
		const vis = Math.min(t, t2);
		const sx = w * 0.1 + (w * 0.8) * (sunAngle / Math.PI);
		const sy = horizonY - Math.sin(sunAngle) * h * 0.45;

		// Glow
		ctx.globalAlpha = vis * 0.15;
		const glow = ctx.createRadialGradient(sx, sy, 0, sx, sy, SUN_MOON_RADIUS * 6);
		glow.addColorStop(0, 'rgba(255, 220, 100, 0.8)');
		glow.addColorStop(1, 'rgba(255, 220, 100, 0)');
		ctx.fillStyle = glow;
		ctx.beginPath();
		ctx.arc(sx, sy, SUN_MOON_RADIUS * 6, 0, TAU);
		ctx.fill();

		// Disc
		ctx.globalAlpha = vis * 0.9;
		ctx.fillStyle = '#ffe082';
		ctx.beginPath();
		ctx.arc(sx, sy, SUN_MOON_RADIUS, 0, TAU);
		ctx.fill();
	}

	// Moon
	if (hour >= 19 || hour <= 7) {
		const adjustedHour = hour < 7 ? hour + 24 : hour;
		const t = Math.max(0, Math.min(1, (adjustedHour - 19) / 1.5));
		const t2 = Math.max(0, Math.min(1, (31 - adjustedHour) / 1.5));
		const vis = Math.min(t, t2);
		const mx = w * 0.1 + (w * 0.8) * (moonAngle / Math.PI);
		const my = horizonY - Math.sin(moonAngle) * h * 0.4;

		// Glow
		ctx.globalAlpha = vis * 0.08;
		const glow = ctx.createRadialGradient(mx, my, 0, mx, my, SUN_MOON_RADIUS * 5);
		glow.addColorStop(0, 'rgba(200, 220, 255, 0.6)');
		glow.addColorStop(1, 'rgba(200, 220, 255, 0)');
		ctx.fillStyle = glow;
		ctx.beginPath();
		ctx.arc(mx, my, SUN_MOON_RADIUS * 5, 0, TAU);
		ctx.fill();

		// Disc
		ctx.globalAlpha = vis * 0.85;
		ctx.fillStyle = '#d4dff0';
		ctx.beginPath();
		ctx.arc(mx, my, SUN_MOON_RADIUS * 0.85, 0, TAU);
		ctx.fill();

		// Crescent shadow
		ctx.globalAlpha = vis * 0.85;
		ctx.fillStyle = `rgb(${skyColor.topR}, ${skyColor.topG}, ${skyColor.topB})`;
		ctx.beginPath();
		ctx.arc(mx + SUN_MOON_RADIUS * 0.35, my - SUN_MOON_RADIUS * 0.1,
			SUN_MOON_RADIUS * 0.7, 0, TAU);
		ctx.fill();
	}
}

// ── Main render ──
function animate() {
	if (!ctx) return;

	const now = new Date();
	const hour = now.getHours() + now.getMinutes() / 60 + now.getSeconds() / 3600;
	const timeSec = performance.now() / 1000;

	// Sky gradient
	const sky = lerpColor(SKY_STOPS, hour);
	const grad = ctx.createLinearGradient(0, 0, 0, h * 0.7);
	grad.addColorStop(0, `rgb(${sky.topR}, ${sky.topG}, ${sky.topB})`);
	grad.addColorStop(1, `rgb(${sky.botR}, ${sky.botG}, ${sky.botB})`);
	ctx.globalAlpha = 1;
	ctx.fillStyle = grad;
	ctx.fillRect(0, 0, w, h);

	// Fill below horizon with darkest mountain color
	const darkness = 0.3 + (MOUNTAIN_LAYERS - 1) * 0.25;
	ctx.fillStyle = `rgb(${Math.round(sky.botR * (1 - darkness))}, ${Math.round(sky.botG * (1 - darkness))}, ${Math.round(sky.botB * (1 - darkness))})`;
	ctx.fillRect(0, h * (1 - TERRAIN_HEIGHT * 0.4), w, h * TERRAIN_HEIGHT * 0.4);

	// Night alpha (for stars and shooting stars)
	let nightAlpha = 0;
	if (hour < 5) nightAlpha = 1;
	else if (hour < 7) nightAlpha = (7 - hour) / 2;
	else if (hour > 20) nightAlpha = (hour - 20) / 1.5;
	else if (hour > 19) nightAlpha = (hour - 19) * 0.3;
	nightAlpha = Math.max(0, Math.min(1, nightAlpha));

	// Stars
	drawStars(nightAlpha, timeSec);

	// Shooting stars
	if (nightAlpha > 0.3 && Math.random() < SHOOTING_STAR_CHANCE) spawnShootingStar();
	updateAndDrawShootingStars(nightAlpha);

	// Sun / Moon
	drawCelestialBody(hour, sky);

	// Clouds
	const cloudBrightness = Math.max(0.15, Math.min(1, 1 - nightAlpha * 0.7));
	drawClouds(cloudBrightness);

	// Mountains (foreground)
	drawMountains(sky);

	// Time label
	if (SHOW_TIME_LABEL) {
		ctx.globalAlpha = 0.2;
		ctx.fillStyle = 'white';
		ctx.font = TIME_LABEL_FONT;
		ctx.textAlign = 'right';
		ctx.textBaseline = 'bottom';
		const h12 = now.getHours() % 12 || 12;
		const ampm = now.getHours() >= 12 ? 'PM' : 'AM';
		const pad = (n) => n < 10 ? '0' + n : '' + n;
		ctx.fillText(
			h12 + ':' + pad(now.getMinutes()) + ':' + pad(now.getSeconds()) + ' ' + ampm,
			w - 14, h - 12
		);
		ctx.globalAlpha = 1;
	}

	requestAnimationFrame(animate);
}

// ── Message handler ──
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initStars();
			initClouds();
			initMountains();
			animate();
			break;

		case 'resize':
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initStars();
			initClouds();
			initMountains();
			break;
	}
};

/**
 * Title: Magnetic Field
 * Description: Magnetic field line visualization with multiple dipoles. Field lines are traced
 *   via Euler integration from N to S poles with color mapped to field strength. Thousands of
 *   iron filing segments orient along the local field direction. Dipoles orbit slowly, causing
 *   dynamic topology reconfiguration. Mouse acts as a strong dipole.
 *   Uses Float32Array bulk storage, spatial hashing for filings, and delta-time animation.
 */

// ─── CONFIG ────────────────────────────────────────────────────────────────────
const CONFIG = {
	dipoleCount: 4, // Number of magnetic dipoles
	dipoleSeparation: 30, // Distance between N and S poles of each dipole (px)
	dipoleStrength: 6000, // Magnetic moment strength of each dipole
	fieldLineCount: 14, // Number of field lines traced per N pole
	fieldLineSteps: 300, // Maximum integration steps per field line
	fieldLineStepSize: 3, // Step size for Euler integration (px)
	ironFilingCount: 2500, // Number of iron filing segments scattered across canvas
	ironFilingLength: 8, // Length of each iron filing segment (px)
	ironFilingAlpha: 0.25, // Base opacity of iron filings
	fieldColorHue: 200, // Base hue for field visualization
	fieldColorIntensity: 1.2, // Multiplier for brightness mapping from field strength
	dipoleOrbitSpeed: 0.003, // Angular velocity of dipole orbital drift (rad/frame)
	dipoleOrbitRadius: 120, // Radius of the slow orbital path of each dipole
	mouseDipoleStrength: 10000, // Strength of the mouse-controlled dipole
	lineWidth: 1.2, // Width of field lines
	lineAlphaBase: 0.35, // Base alpha for field lines
	filingResetRate: 0.002, // Fraction of filings repositioned per frame (keeps it fresh)
	glowPasses: 2, // Multi-pass glow layers for field lines
	glowWidthStep: 3, // Width increase per glow pass
	glowAlphaDecay: 0.3, // Alpha decay per glow pass
	poleGlowRadius: 25 // Visual glow radius around pole markers
};

// ─── STATE ─────────────────────────────────────────────────────────────────────
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;

// Dipole storage: each dipole has a center, angle, and generates two poles
let dipoles = [];

// Iron filing positions — Float32Array for performance
let filingX, filingY;

// Precomputed pole positions (N and S for each dipole + mouse dipole)
// Updated each frame
let poleX, poleY, poleSign, poleStrength;
let poleCount = 0;

// ─── HEARTBEAT ─────────────────────────────────────────────────────────────────
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── DIPOLE CLASS ──────────────────────────────────────────────────────────────
class Dipole {
	constructor(cx, cy, angle, strength) {
		this.cx = cx;
		this.cy = cy;
		this.angle = angle;
		this.strength = strength;
		this.orbitAngle = Math.random() * Math.PI * 2;
		this.orbitCx = cx;
		this.orbitCy = cy;
		this.hue = Math.random() * 60 + CONFIG.fieldColorHue - 30;
	}

	update(dt) {
		this.orbitAngle += CONFIG.dipoleOrbitSpeed * dt;
		this.cx = this.orbitCx + Math.cos(this.orbitAngle) * CONFIG.dipoleOrbitRadius;
		this.cy = this.orbitCy + Math.sin(this.orbitAngle) * CONFIG.dipoleOrbitRadius;
		// Slowly rotate the dipole itself
		this.angle += CONFIG.dipoleOrbitSpeed * 0.5 * dt;
	}

	getNPole() {
		const half = CONFIG.dipoleSeparation * 0.5;
		return {
			x: this.cx + Math.cos(this.angle) * half,
			y: this.cy + Math.sin(this.angle) * half
		};
	}

	getSPole() {
		const half = CONFIG.dipoleSeparation * 0.5;
		return {
			x: this.cx - Math.cos(this.angle) * half,
			y: this.cy - Math.sin(this.angle) * half
		};
	}
}

// ─── FIELD COMPUTATION ─────────────────────────────────────────────────────────
// Returns { bx, by } — the magnetic field vector at point (x, y)
// Each pole contributes a monopole-like field: B = strength * sign / r^2, direction = r_hat * sign
function computeField(x, y) {
	let bx = 0,
		by = 0;

	for (let i = 0; i < poleCount; i++) {
		const dx = x - poleX[i];
		const dy = y - poleY[i];
		const dist2 = dx * dx + dy * dy + 100; // Softening to prevent singularities
		const dist = Math.sqrt(dist2);
		const factor = (poleStrength[i] * poleSign[i]) / (dist2 * dist);
		bx += dx * factor;
		by += dy * factor;
	}

	return { bx, by };
}

function fieldMagnitude(bx, by) {
	return Math.sqrt(bx * bx + by * by);
}

// ─── INITIALIZATION ────────────────────────────────────────────────────────────
function initDipoles() {
	dipoles = [];
	const cx = width * 0.5;
	const cy = height * 0.5;
	const spread = Math.min(width, height) * 0.25;

	for (let i = 0; i < CONFIG.dipoleCount; i++) {
		const angle = (i / CONFIG.dipoleCount) * Math.PI * 2;
		const x = cx + Math.cos(angle) * spread;
		const y = cy + Math.sin(angle) * spread;
		const dipAngle = angle + Math.PI * 0.5 + (Math.random() - 0.5) * 1;
		dipoles.push(new Dipole(x, y, dipAngle, CONFIG.dipoleStrength));
	}

	// Allocate pole arrays: each dipole = 2 poles + mouse dipole (2 poles)
	const maxPoles = (CONFIG.dipoleCount + 1) * 2;
	poleX = new Float32Array(maxPoles);
	poleY = new Float32Array(maxPoles);
	poleSign = new Float32Array(maxPoles);
	poleStrength = new Float32Array(maxPoles);
}

function initFilings() {
	const n = CONFIG.ironFilingCount;
	filingX = new Float32Array(n);
	filingY = new Float32Array(n);

	for (let i = 0; i < n; i++) {
		filingX[i] = Math.random() * width;
		filingY[i] = Math.random() * height;
	}
}

function updatePolePositions() {
	poleCount = 0;

	for (let i = 0; i < dipoles.length; i++) {
		const d = dipoles[i];
		const np = d.getNPole();
		const sp = d.getSPole();

		poleX[poleCount] = np.x;
		poleY[poleCount] = np.y;
		poleSign[poleCount] = 1;
		poleStrength[poleCount] = d.strength;
		poleCount++;

		poleX[poleCount] = sp.x;
		poleY[poleCount] = sp.y;
		poleSign[poleCount] = -1;
		poleStrength[poleCount] = d.strength;
		poleCount++;
	}

	// Mouse dipole (horizontal orientation)
	if (mouse.x > -1000) {
		const sep = CONFIG.dipoleSeparation * 0.5;
		poleX[poleCount] = mouse.x + sep;
		poleY[poleCount] = mouse.y;
		poleSign[poleCount] = 1;
		poleStrength[poleCount] = CONFIG.mouseDipoleStrength;
		poleCount++;

		poleX[poleCount] = mouse.x - sep;
		poleY[poleCount] = mouse.y;
		poleSign[poleCount] = -1;
		poleStrength[poleCount] = CONFIG.mouseDipoleStrength;
		poleCount++;
	}
}

// ─── RENDERING ─────────────────────────────────────────────────────────────────
function traceFieldLine(ctx, startX, startY, direction, pass) {
	const steps = CONFIG.fieldLineSteps;
	const stepSize = CONFIG.fieldLineStepSize * direction;
	const isGlow = pass > 0;
	const extraWidth = isGlow ? pass * CONFIG.glowWidthStep : 0;
	const alphaScale = isGlow ? Math.pow(CONFIG.glowAlphaDecay, pass) : 1;

	let x = startX;
	let y = startY;

	ctx.beginPath();
	ctx.moveTo(x, y);

	let prevStrength = 0;
	let segmentCount = 0;

	for (let s = 0; s < steps; s++) {
		const { bx, by } = computeField(x, y);
		const mag = fieldMagnitude(bx, by);
		if (mag < 0.0001) break;

		// Normalize and step
		const nx = bx / mag;
		const ny = by / mag;
		x += nx * stepSize;
		y += ny * stepSize;

		// Off-screen culling — stop tracing
		if (x < -50 || x > width + 50 || y < -50 || y > height + 50) break;

		// Check if we've reached a pole (close to any S pole)
		let hitPole = false;
		for (let p = 0; p < poleCount; p++) {
			if (poleSign[p] !== -direction) continue;
			const dx = x - poleX[p];
			const dy = y - poleY[p];
			if (dx * dx + dy * dy < 100) {
				hitPole = true;
				break;
			}
		}

		ctx.lineTo(x, y);
		segmentCount++;

		if (hitPole) break;
		prevStrength = mag;
	}

	if (segmentCount < 3) return;

	// Color based on average field strength
	const intensity = Math.min(prevStrength * CONFIG.fieldColorIntensity * 500, 1);
	const hue = CONFIG.fieldColorHue + intensity * 40;
	const lightness = 40 + intensity * 30;
	const alpha = (CONFIG.lineAlphaBase + intensity * 0.3) * alphaScale;

	ctx.strokeStyle = `hsla(${hue}, 70%, ${lightness}%, ${alpha})`;
	ctx.lineWidth = CONFIG.lineWidth + extraWidth;
	ctx.lineCap = 'round';
	ctx.stroke();
}

function drawFieldLines(ctx) {
	// Trace field lines from each N pole
	for (let p = 0; p < poleCount; p++) {
		if (poleSign[p] !== 1) continue; // Only start from N poles

		const cx = poleX[p];
		const cy = poleY[p];

		for (let i = 0; i < CONFIG.fieldLineCount; i++) {
			const angle = (i / CONFIG.fieldLineCount) * Math.PI * 2;
			const startR = 8;
			const sx = cx + Math.cos(angle) * startR;
			const sy = cy + Math.sin(angle) * startR;

			// Multi-pass glow
			for (let pass = CONFIG.glowPasses; pass >= 0; pass--) {
				traceFieldLine(ctx, sx, sy, 1, pass);
			}
		}
	}
}

function drawIronFilings(ctx) {
	const halfLen = CONFIG.ironFilingLength * 0.5;
	const resetCount = Math.ceil(CONFIG.ironFilingCount * CONFIG.filingResetRate);

	// Randomly reposition a few filings each frame for visual freshness
	for (let i = 0; i < resetCount; i++) {
		const idx = Math.floor(Math.random() * CONFIG.ironFilingCount);
		filingX[idx] = Math.random() * width;
		filingY[idx] = Math.random() * height;
	}

	ctx.lineWidth = 1;
	ctx.lineCap = 'round';

	// Batch by starting a single path and drawing all filings
	for (let i = 0; i < CONFIG.ironFilingCount; i++) {
		const x = filingX[i];
		const y = filingY[i];

		// Off-screen culling
		if (x < -10 || x > width + 10 || y < -10 || y > height + 10) continue;

		const { bx, by } = computeField(x, y);
		const mag = fieldMagnitude(bx, by);
		if (mag < 0.0001) continue;

		const nx = bx / mag;
		const ny = by / mag;
		const intensity = Math.min(mag * 600, 1);
		const alpha = CONFIG.ironFilingAlpha * (0.3 + intensity * 0.7);

		ctx.beginPath();
		ctx.moveTo(x - nx * halfLen, y - ny * halfLen);
		ctx.lineTo(x + nx * halfLen, y + ny * halfLen);
		ctx.strokeStyle = `hsla(${CONFIG.fieldColorHue + intensity * 30}, 50%, ${50 + intensity * 30}%, ${alpha})`;
		ctx.stroke();
	}
}

function drawPoles(ctx) {
	for (let i = 0; i < poleCount; i++) {
		const x = poleX[i];
		const y = poleY[i];
		const isN = poleSign[i] > 0;
		const r = CONFIG.poleGlowRadius;

		// Glow
		const grad = ctx.createRadialGradient(x, y, 0, x, y, r);
		const hue = isN ? 0 : 220;
		grad.addColorStop(0, `hsla(${hue}, 80%, 70%, 0.3)`);
		grad.addColorStop(0.5, `hsla(${hue}, 80%, 50%, 0.1)`);
		grad.addColorStop(1, `hsla(${hue}, 80%, 30%, 0)`);
		ctx.fillStyle = grad;
		ctx.fillRect(x - r, y - r, r * 2, r * 2);

		// Core dot
		ctx.beginPath();
		ctx.arc(x, y, 4, 0, Math.PI * 2);
		ctx.fillStyle = isN ? 'rgba(255, 100, 100, 0.8)' : 'rgba(100, 150, 255, 0.8)';
		ctx.fill();
	}
}

// ─── MESSAGE HANDLER ───────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initDipoles();
			initFilings();
			lastTime = performance.now();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initFilings();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

// ─── RENDER LOOP ───────────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) return;

		const dt = Math.min((now - lastTime) / 16.667, 3);
		lastTime = now;

		// Clear with slight trail
		ctx.fillStyle = 'rgba(0, 0, 0, 0.12)';
		ctx.fillRect(0, 0, width, height);

		// Update dipole positions
		for (let i = 0; i < dipoles.length; i++) {
			dipoles[i].update(dt);
		}
		updatePolePositions();

		// Render layers
		drawIronFilings(ctx);
		drawFieldLines(ctx);
		drawPoles(ctx);

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Matrix Rain
 * Description: Classic Matrix digital rain with columns of falling katakana, numbers,
 *   and latin characters. Green phosphor glow, brighter leading characters.
 *   Mouse proximity accelerates nearby columns.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

// Column state
let columns = [];
const FONT_SIZE = 14;
const CHAR_POOL =
	'アイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホマミムメモヤユヨラリルレロワヲン' +
	'0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';

// Heartbeat to keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initColumns();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initColumns();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function initColumns() {
	const count = Math.ceil(width / FONT_SIZE);
	columns = [];
	for (let i = 0; i < count; i++) {
		columns.push({
			x: i * FONT_SIZE,
			y: Math.random() * height * -1, // start above screen
			speed: 0.3 + Math.random() * 0.7, // base speed multiplier
			chars: generateChars(Math.ceil(height / FONT_SIZE) + 10),
			length: 8 + Math.floor(Math.random() * 20), // visible trail length
			offset: 0 // fractional y offset for smooth scrolling
		});
	}
}

function generateChars(count) {
	const chars = [];
	for (let i = 0; i < count; i++) {
		chars.push(CHAR_POOL[Math.floor(Math.random() * CHAR_POOL.length)]);
	}
	return chars;
}

function randomChar() {
	return CHAR_POOL[Math.floor(Math.random() * CHAR_POOL.length)];
}

function startAnimation() {
	let lastTime = 0;

	function render(time) {
		if (!ctx) return;
		const dt = lastTime ? (time - lastTime) / 16.67 : 1; // normalize to ~60fps
		lastTime = time;

		// Fade the canvas instead of clearing — creates the trail effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
		ctx.fillRect(0, 0, width, height);

		ctx.font = `${FONT_SIZE}px monospace`;

		for (let i = 0; i < columns.length; i++) {
			const col = columns[i];

			// Mouse proximity check — speed boost for nearby columns
			const dx = col.x - mouse.x;
			const dist = Math.abs(dx);
			const mouseBoost = dist < 200 ? 1 + (1 - dist / 200) * 2.5 : 1;

			// Advance the column
			col.offset += col.speed * mouseBoost * dt;

			// When we've moved a full character height, shift everything
			if (col.offset >= FONT_SIZE) {
				col.offset -= FONT_SIZE;
				col.y += FONT_SIZE;

				// Randomly mutate a character in the trail
				const mutateIdx = Math.floor(Math.random() * col.chars.length);
				col.chars[mutateIdx] = randomChar();
			}

			// Calculate the head position (in cell units)
			const headRow = Math.floor(col.y / FONT_SIZE);

			// Draw visible characters
			for (let j = 0; j < col.length; j++) {
				const row = headRow - j;
				const py = row * FONT_SIZE + col.offset;

				// Skip if off-screen
				if (py < -FONT_SIZE || py > height + FONT_SIZE) continue;

				const charIdx = Math.abs(row) % col.chars.length;
				const ch = col.chars[charIdx];

				if (j === 0) {
					// Leading character — bright white-green
					ctx.fillStyle = 'rgba(180, 255, 180, 0.95)';
					ctx.shadowColor = 'rgba(0, 255, 70, 0.8)';
					ctx.shadowBlur = 12;
				} else if (j === 1) {
					// Second char — still bright
					ctx.fillStyle = 'rgba(0, 255, 70, 0.7)';
					ctx.shadowColor = 'rgba(0, 255, 70, 0.4)';
					ctx.shadowBlur = 6;
				} else {
					// Trail — fades out
					const fade = 1 - j / col.length;
					const alpha = fade * 0.4;
					ctx.fillStyle = `rgba(0, 200, 50, ${alpha})`;
					ctx.shadowBlur = 0;
				}

				ctx.fillText(ch, col.x, py);
			}

			// Reset shadow after each column
			ctx.shadowBlur = 0;

			// Reset column when it's fully off the bottom
			if ((headRow - col.length) * FONT_SIZE > height) {
				col.y = Math.random() * -height * 0.5 - FONT_SIZE * col.length;
				col.speed = 0.3 + Math.random() * 0.7;
				col.length = 8 + Math.floor(Math.random() * 20);
				col.chars = generateChars(Math.ceil(height / FONT_SIZE) + 10);
			}
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Matrix Rain Japanese
 * Description: Cascading columns of glowing Japanese Katakana characters that
 *   fade to transparency. Each column resets at random intervals with a bright
 *   green glow that decays as it falls.
 */
// DigitalRain – transparency-optimized
let c,ctx,w,h,cols=[],font=15,glow=[]; 
self.onmessage=e=>{
  if(e.data.type==='init'){
    c=e.data.canvas;ctx=c.getContext('2d');
    w=c.width=e.data.width;h=c.height=e.data.height;
    ctx.font=font+'px monospace';
    let colCount=Math.floor(w/font);
    for(let i=0;i<colCount;i++){
      cols[i]=Math.random()*h;
      glow[i]=Math.random();
    }
    animate();
  }
  if(e.data.type==='resize'){
    w=c.width=e.data.width;h=c.height=e.data.height;
    ctx.font=font+'px monospace';
    let colCount=Math.floor(w/font);
    let oldLen=cols.length;
    cols.length=colCount;
    glow.length=colCount;
    for(let i=oldLen;i<colCount;i++){
      cols[i]=Math.random()*h;
      glow[i]=Math.random();
    }
  }
};
function animate(){
  // 1. Erase a portion of the previous frame to transparency
  ctx.globalCompositeOperation = 'destination-out';
  ctx.fillStyle='rgba(0,0,0,0.1)';
  ctx.fillRect(0,0,w,h);

  // 2. Switch back to normal drawing mode for characters
  ctx.globalCompositeOperation = 'source-over';

  let colCount=Math.floor(w/font);
  for(let i=0;i<colCount;i++){
    let txt=String.fromCharCode(0x30A0+Math.random()*96|0);
    let y=cols[i];
    ctx.fillStyle='hsla(120,100%,'+glow[i]*70+'%,1)';
    ctx.fillText(txt,i*font,y);
    cols[i]+=font*0.8;
    glow[i]*=0.98;
    if(y>h&&Math.random()<0.02){cols[i]=0;glow[i]=1;}
  }
  requestAnimationFrame(animate);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Morphing Polygons
 * Description: Several large semi-transparent polygons that slowly morph between
 * different shapes (triangle → square → pentagon → hexagon → circle) using vertex
 * interpolation. They drift lazily and overlap with blend effects. Mouse proximity
 * speeds up the morphing.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let polygons = [];
let lastTime = 0;

// Shape definitions — number of vertices for each stage
const SHAPES = [3, 4, 5, 6, 12]; // triangle, square, pentagon, hexagon, ~circle
const MAX_VERTICES = 12; // Normalize all shapes to this vertex count
const NUM_POLYGONS = 6;
const BASE_MORPH_SPEED = 0.08; // Morphs per second
const MOUSE_INFLUENCE = 300;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initPolygons();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			// Reposition polygons within new bounds
			for (const p of polygons) {
				p.x = Math.min(p.x, width);
				p.y = Math.min(p.y, height);
			}
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Generate normalized vertices for a regular polygon with `sides` vertices,
 * upsampled to MAX_VERTICES points for smooth interpolation.
 */
function generateShape(sides) {
	const points = [];
	for (let i = 0; i < MAX_VERTICES; i++) {
		// Map each of the MAX_VERTICES points to a position on the polygon
		const t = i / MAX_VERTICES;
		const angle = t * Math.PI * 2 - Math.PI / 2;

		// For a regular polygon with `sides`, find the radius at this angle
		const sectorAngle = (Math.PI * 2) / sides;
		const localAngle = ((angle % sectorAngle) + sectorAngle) % sectorAngle;
		const halfSector = sectorAngle / 2;
		const r = Math.cos(halfSector) / Math.cos(localAngle - halfSector);

		points.push({
			x: Math.cos(angle) * r,
			y: Math.sin(angle) * r
		});
	}
	return points;
}

// Pre-generate all shape vertices
const shapeVertices = SHAPES.map((s) => generateShape(s));

function initPolygons() {
	polygons = [];
	const colors = [
		[120, 160, 255],
		[180, 120, 255],
		[100, 220, 200],
		[255, 150, 120],
		[200, 200, 100],
		[150, 180, 220]
	];

	for (let i = 0; i < NUM_POLYGONS; i++) {
		const radius = 80 + Math.random() * 120;
		polygons.push({
			x: Math.random() * width,
			y: Math.random() * height,
			vx: (Math.random() - 0.5) * 15,
			vy: (Math.random() - 0.5) * 15,
			radius,
			rotation: Math.random() * Math.PI * 2,
			rotationSpeed: (Math.random() - 0.5) * 0.15,
			shapeIndex: Math.floor(Math.random() * SHAPES.length),
			morphProgress: 0,
			color: colors[i % colors.length],
			opacity: 0.04 + Math.random() * 0.06
		});
	}
}

function lerp(a, b, t) {
	return a + (b - a) * t;
}

function lerpPoint(a, b, t) {
	return { x: lerp(a.x, b.x, t), y: lerp(a.y, b.y, t) };
}

// Smooth easing
function easeInOut(t) {
	return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
}

function startAnimation() {
	lastTime = performance.now() / 1000;

	function render() {
		if (!ctx) return;

		const now = performance.now() / 1000;
		const dt = Math.min(now - lastTime, 0.05);
		lastTime = now;

		ctx.clearRect(0, 0, width, height);

		// Use lighter composite for overlapping glow
		ctx.globalCompositeOperation = 'lighter';

		for (const poly of polygons) {
			// Mouse distance for speed boost
			const mouseDist = Math.hypot(poly.x - mouse.x, poly.y - mouse.y);
			const mouseBoost =
				mouseDist < MOUSE_INFLUENCE ? 1 + (1 - mouseDist / MOUSE_INFLUENCE) * 4 : 1;

			// Advance morph
			poly.morphProgress += BASE_MORPH_SPEED * mouseBoost * dt;

			if (poly.morphProgress >= 1) {
				poly.morphProgress -= 1;
				poly.shapeIndex = (poly.shapeIndex + 1) % SHAPES.length;
			}

			// Drift movement
			poly.x += poly.vx * dt;
			poly.y += poly.vy * dt;
			poly.rotation += poly.rotationSpeed * dt;

			// Wrap around edges with padding
			const pad = poly.radius * 1.5;
			if (poly.x < -pad) poly.x = width + pad;
			if (poly.x > width + pad) poly.x = -pad;
			if (poly.y < -pad) poly.y = height + pad;
			if (poly.y > height + pad) poly.y = -pad;

			// Get current and next shape vertices
			const currentShape = shapeVertices[poly.shapeIndex];
			const nextShape = shapeVertices[(poly.shapeIndex + 1) % SHAPES.length];
			const t = easeInOut(poly.morphProgress);

			// Draw interpolated shape
			ctx.save();
			ctx.translate(poly.x, poly.y);
			ctx.rotate(poly.rotation);

			ctx.beginPath();
			for (let i = 0; i < MAX_VERTICES; i++) {
				const pt = lerpPoint(currentShape[i], nextShape[i], t);
				const px = pt.x * poly.radius;
				const py = pt.y * poly.radius;
				if (i === 0) ctx.moveTo(px, py);
				else ctx.lineTo(px, py);
			}
			ctx.closePath();

			// Fill
			const [r, g, b] = poly.color;
			ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${poly.opacity})`;
			ctx.fill();

			// Stroke
			ctx.strokeStyle = `rgba(${r}, ${g}, ${b}, ${poly.opacity * 2.5})`;
			ctx.lineWidth = 1.2;
			ctx.stroke();

			ctx.restore();
		}

		// Reset composite
		ctx.globalCompositeOperation = 'source-over';

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Mycelium Network
 * Description: An organic fungal mycelium that grows outward from seed points,
 *   branching stochastically. Nutrient pulses race along established connections,
 *   mature nodes release spores, and the mouse acts as a nutrient source that
 *   accelerates nearby growth and attracts branching direction.
 */

// ─── CONFIG ──────────────────────────────────────────────────────────────────
const CONFIG = {
	seedCount: 4, // number of initial growth origin points
	growthSpeed: 40, // px/s – base tip extension speed
	growthAngleVariance: 0.35, // radians – max random wander per step
	branchProbability: 0.012, // per-frame chance of branching at a tip
	branchAngleRange: 0.8, // radians – max branch fork angle
	maxBranchDepth: 7, // maximum recursive branching depth
	maxSegments: 4000, // hard cap on total hypha segments
	hyphaWidth: 1.5, // px – base strand thickness
	hyphaAlpha: 0.6, // base alpha of hypha strands
	pulseSpeed: 120, // px/s – speed of nutrient pulses
	pulseFrequency: 0.3, // pulses spawned per second per seed
	pulseGlow: 8, // px – glow radius around a pulse dot
	pulseSize: 3, // px – core radius of pulse dot
	nodeGlowRadius: 12, // px – glow at branch intersection nodes
	nodeGlowAlpha: 0.15, // alpha of node glow
	fadeRate: 0.0008, // alpha decay per second for old segments
	sporeCount: 5, // spores per burst
	sporeSpeed: 25, // px/s – spore drift speed
	sporeLifetime: 3.0, // seconds before spore fades
	sporeBurstChance: 0.005, // per-frame chance a mature node bursts
	mouseNutrientRadius: 200, // px – radius of mouse nutrient influence
	mouseGrowthBoost: 2.5, // multiplier for growth speed near mouse
	mouseBranchBoost: 3.0, // multiplier for branch probability near mouse
	baseHue: 80, // HSL hue (80 = yellow-green)
	hueVariance: 30, // random hue offset range
	glowPasses: 2, // additive glow passes for the network
	glowExpand: 4, // px – extra width per glow pass
	glowAlpha: 0.04, // alpha per glow pass
	trailAlpha: 0.03, // motion trail decay alpha
	layerCount: 3, // parallax depth layers
	layerAlphaScale: 0.4 // alpha multiplier for the deepest layer
};

// ─── GLOBALS ─────────────────────────────────────────────────────────────────
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;

// Segment storage: Float32Array columns (x1,y1,x2,y2,age,branchDepth,layer,hue)
const SEG_STRIDE = 8;
let segments = null; // Float32Array
let segCount = 0;

// Active tips: objects with {x,y,angle,depth,layer,hue,active}
let tips = [];
const MAX_TIPS = 500;

// Pulses: {segIndex, t, speed, layer}
let pulses = [];
const MAX_PULSES = 200;

// Spores: Float32Array (x,y,vx,vy,life,maxLife,layer)
const SPORE_STRIDE = 7;
let spores = null;
let sporeCount = 0;
const MAX_SPORES = 300;

// Nodes (branch points): Float32Array (x,y,age,layer)
const NODE_STRIDE = 4;
let nodes = null;
let nodeCount = 0;
const MAX_NODES = 800;

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── INIT ────────────────────────────────────────────────────────────────────
function initAll() {
	segments = new Float32Array(CONFIG.maxSegments * SEG_STRIDE);
	segCount = 0;
	tips = [];
	pulses = [];
	spores = new Float32Array(MAX_SPORES * SPORE_STRIDE);
	sporeCount = 0;
	nodes = new Float32Array(MAX_NODES * NODE_STRIDE);
	nodeCount = 0;
	lastTime = 0;

	// Seed points
	for (let i = 0; i < CONFIG.seedCount; i++) {
		const layer = i % CONFIG.layerCount;
		tips.push({
			x: width * 0.2 + Math.random() * width * 0.6,
			y: height * 0.2 + Math.random() * height * 0.6,
			angle: Math.random() * Math.PI * 2,
			depth: 0,
			layer,
			hue: CONFIG.baseHue + (Math.random() - 0.5) * CONFIG.hueVariance,
			active: true
		});
	}
}

// ─── SPATIAL HASH (for node proximity) ──────────────────────────────────────
const CELL_SIZE = 50;
let hashMap = new Map();

function hashKey(x, y) {
	return ((x / CELL_SIZE) | 0) * 100000 + ((y / CELL_SIZE) | 0);
}

function rebuildHash() {
	hashMap.clear();
	for (let i = 0; i < segCount; i++) {
		const off = i * SEG_STRIDE;
		const key = hashKey(segments[off + 2], segments[off + 3]);
		if (!hashMap.has(key)) hashMap.set(key, []);
		hashMap.get(key).push(i);
	}
}

function nearbySegCount(x, y, radius) {
	let count = 0;
	const cells = Math.ceil(radius / CELL_SIZE);
	const cx = (x / CELL_SIZE) | 0;
	const cy = (y / CELL_SIZE) | 0;
	for (let dx = -cells; dx <= cells; dx++) {
		for (let dy = -cells; dy <= cells; dy++) {
			const key = (cx + dx) * 100000 + (cy + dy);
			const bucket = hashMap.get(key);
			if (bucket) count += bucket.length;
		}
	}
	return count;
}

// ─── UPDATE ──────────────────────────────────────────────────────────────────
function update(dt) {
	// Grow tips
	const activeTips = [];
	for (const tip of tips) {
		if (!tip.active) continue;
		if (segCount >= CONFIG.maxSegments) {
			tip.active = false;
			continue;
		}

		// Mouse influence
		const dx = mouse.x - tip.x;
		const dy = mouse.y - tip.y;
		const distMouse = Math.sqrt(dx * dx + dy * dy);
		const mouseInfluence =
			distMouse < CONFIG.mouseNutrientRadius ? 1 - distMouse / CONFIG.mouseNutrientRadius : 0;

		const speed = CONFIG.growthSpeed * (1 + mouseInfluence * (CONFIG.mouseGrowthBoost - 1));

		// Steer toward mouse slightly
		if (mouseInfluence > 0) {
			const toMouse = Math.atan2(dy, dx);
			let angleDiff = toMouse - tip.angle;
			while (angleDiff > Math.PI) angleDiff -= Math.PI * 2;
			while (angleDiff < -Math.PI) angleDiff += Math.PI * 2;
			tip.angle += angleDiff * 0.1 * mouseInfluence;
		}

		// Wander
		tip.angle += (Math.random() - 0.5) * CONFIG.growthAngleVariance;

		const nx = tip.x + Math.cos(tip.angle) * speed * dt;
		const ny = tip.y + Math.sin(tip.angle) * speed * dt;

		// Cull if off-screen
		if (nx < -50 || nx > width + 50 || ny < -50 || ny > height + 50) {
			tip.active = false;
			continue;
		}

		// Store segment
		const off = segCount * SEG_STRIDE;
		segments[off + 0] = tip.x;
		segments[off + 1] = tip.y;
		segments[off + 2] = nx;
		segments[off + 3] = ny;
		segments[off + 4] = 0; // age
		segments[off + 5] = tip.depth;
		segments[off + 6] = tip.layer;
		segments[off + 7] = tip.hue;
		segCount++;

		tip.x = nx;
		tip.y = ny;

		// Branching
		const branchProb =
			CONFIG.branchProbability * (1 + mouseInfluence * (CONFIG.mouseBranchBoost - 1));
		if (Math.random() < branchProb && tip.depth < CONFIG.maxBranchDepth && tips.length < MAX_TIPS) {
			const branchAngle = tip.angle + (Math.random() - 0.5) * CONFIG.branchAngleRange;
			tips.push({
				x: nx,
				y: ny,
				angle: branchAngle,
				depth: tip.depth + 1,
				layer: tip.layer,
				hue: tip.hue + (Math.random() - 0.5) * 10,
				active: true
			});
			// Store branch node
			if (nodeCount < MAX_NODES) {
				const noff = nodeCount * NODE_STRIDE;
				nodes[noff + 0] = nx;
				nodes[noff + 1] = ny;
				nodes[noff + 2] = 0;
				nodes[noff + 3] = tip.layer;
				nodeCount++;
			}
		}

		activeTips.push(tip);
	}

	// Age segments
	for (let i = 0; i < segCount; i++) {
		segments[i * SEG_STRIDE + 4] += dt;
	}
	for (let i = 0; i < nodeCount; i++) {
		nodes[i * NODE_STRIDE + 2] += dt;
	}

	// Spawn pulses
	if (segCount > 10 && pulses.length < MAX_PULSES) {
		if (Math.random() < CONFIG.pulseFrequency * dt) {
			pulses.push({
				segIndex: Math.floor(Math.random() * segCount),
				t: 0,
				speed: CONFIG.pulseSpeed,
				layer: Math.floor(Math.random() * CONFIG.layerCount)
			});
		}
	}

	// Update pulses
	for (let i = pulses.length - 1; i >= 0; i--) {
		pulses[i].t += CONFIG.pulseSpeed * dt;
		const si = pulses[i].segIndex;
		if (si >= segCount || pulses[i].t > 1) {
			// Move to next segment or remove
			const nextSeg = si + 1;
			if (nextSeg < segCount) {
				pulses[i].segIndex = nextSeg;
				pulses[i].t = 0;
			} else {
				pulses.splice(i, 1);
			}
		}
	}

	// Spore bursts from mature nodes
	for (let i = 0; i < nodeCount; i++) {
		const noff = i * NODE_STRIDE;
		if (nodes[noff + 2] > 5 && Math.random() < CONFIG.sporeBurstChance) {
			for (let s = 0; s < CONFIG.sporeCount && sporeCount < MAX_SPORES; s++) {
				const soff = sporeCount * SPORE_STRIDE;
				const angle = Math.random() * Math.PI * 2;
				spores[soff + 0] = nodes[noff + 0];
				spores[soff + 1] = nodes[noff + 1];
				spores[soff + 2] = Math.cos(angle) * CONFIG.sporeSpeed * (0.5 + Math.random());
				spores[soff + 3] = Math.sin(angle) * CONFIG.sporeSpeed * (0.5 + Math.random());
				spores[soff + 4] = CONFIG.sporeLifetime;
				spores[soff + 5] = CONFIG.sporeLifetime;
				spores[soff + 6] = nodes[noff + 3]; // layer
				sporeCount++;
			}
		}
	}

	// Update spores
	let aliveSpores = 0;
	for (let i = 0; i < sporeCount; i++) {
		const soff = i * SPORE_STRIDE;
		spores[soff + 0] += spores[soff + 2] * dt;
		spores[soff + 1] += spores[soff + 3] * dt;
		spores[soff + 4] -= dt;
		if (spores[soff + 4] > 0) {
			if (aliveSpores !== i) {
				const doff = aliveSpores * SPORE_STRIDE;
				for (let j = 0; j < SPORE_STRIDE; j++) spores[doff + j] = spores[soff + j];
			}
			aliveSpores++;
		}
	}
	sporeCount = aliveSpores;
}

// ─── DRAW ────────────────────────────────────────────────────────────────────
function draw() {
	// Trail overlay
	ctx.fillStyle = `rgba(0,0,0,${CONFIG.trailAlpha})`;
	ctx.fillRect(0, 0, width, height);

	// Draw per layer (back to front)
	for (let layer = CONFIG.layerCount - 1; layer >= 0; layer--) {
		const layerAlpha = 1 - (layer / CONFIG.layerCount) * (1 - CONFIG.layerAlphaScale);

		// Glow passes
		ctx.globalCompositeOperation = 'lighter';
		for (let pass = 0; pass < CONFIG.glowPasses; pass++) {
			const extraW = (pass + 1) * CONFIG.glowExpand;
			const gAlpha = CONFIG.glowAlpha / (pass + 1);
			drawSegments(layer, layerAlpha * gAlpha, CONFIG.hyphaWidth + extraW);
		}

		// Solid pass
		ctx.globalCompositeOperation = 'source-over';
		drawSegments(layer, layerAlpha, CONFIG.hyphaWidth);

		// Nodes
		drawNodes(layer, layerAlpha);

		// Pulses
		drawPulses(layer, layerAlpha);

		// Spores
		drawSpores(layer, layerAlpha);
	}
}

function drawSegments(layer, alphaScale, lineWidth) {
	ctx.lineWidth = lineWidth;
	ctx.lineCap = 'round';

	// Batch by similar hue for fewer style changes
	for (let i = 0; i < segCount; i++) {
		const off = i * SEG_STRIDE;
		if (segments[off + 6] !== layer) continue;

		const age = segments[off + 4];
		const depth = segments[off + 5];
		const hue = segments[off + 7];
		const fade = Math.max(0, 1 - age * CONFIG.fadeRate);
		const depthFade = 1 / (1 + depth * 0.15);
		const alpha = CONFIG.hyphaAlpha * fade * depthFade * alphaScale;

		if (alpha < 0.005) continue;

		ctx.beginPath();
		ctx.moveTo(segments[off + 0], segments[off + 1]);
		ctx.lineTo(segments[off + 2], segments[off + 3]);
		ctx.strokeStyle = `hsla(${hue | 0},70%,60%,${alpha.toFixed(3)})`;
		ctx.stroke();
	}
}

function drawNodes(layer, alphaScale) {
	ctx.globalCompositeOperation = 'lighter';
	for (let i = 0; i < nodeCount; i++) {
		const noff = i * NODE_STRIDE;
		if (nodes[noff + 3] !== layer) continue;

		const alpha = CONFIG.nodeGlowAlpha * alphaScale;
		if (alpha < 0.005) continue;

		ctx.beginPath();
		ctx.arc(nodes[noff + 0], nodes[noff + 1], CONFIG.nodeGlowRadius, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(${CONFIG.baseHue},80%,70%,${alpha.toFixed(3)})`;
		ctx.fill();
	}
	ctx.globalCompositeOperation = 'source-over';
}

function drawPulses(layer, alphaScale) {
	ctx.globalCompositeOperation = 'lighter';
	for (const pulse of pulses) {
		if (pulse.layer !== layer) continue;
		const si = pulse.segIndex;
		if (si >= segCount) continue;
		const off = si * SEG_STRIDE;
		const t = pulse.t;
		const px = segments[off + 0] + (segments[off + 2] - segments[off + 0]) * t;
		const py = segments[off + 1] + (segments[off + 3] - segments[off + 1]) * t;

		// Outer glow
		ctx.beginPath();
		ctx.arc(px, py, CONFIG.pulseGlow, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(${CONFIG.baseHue + 30},90%,80%,${(0.15 * alphaScale).toFixed(3)})`;
		ctx.fill();

		// Core
		ctx.beginPath();
		ctx.arc(px, py, CONFIG.pulseSize, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(${CONFIG.baseHue + 30},90%,90%,${(0.7 * alphaScale).toFixed(3)})`;
		ctx.fill();
	}
	ctx.globalCompositeOperation = 'source-over';
}

function drawSpores(layer, alphaScale) {
	for (let i = 0; i < sporeCount; i++) {
		const soff = i * SPORE_STRIDE;
		if (spores[soff + 6] !== layer) continue;
		const life = spores[soff + 4];
		const maxLife = spores[soff + 5];
		const alpha = (life / maxLife) * 0.5 * alphaScale;
		if (alpha < 0.005) continue;
		const r = 1.5 * (life / maxLife);

		ctx.beginPath();
		ctx.arc(spores[soff + 0], spores[soff + 1], r, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(${CONFIG.baseHue + 40},60%,80%,${alpha.toFixed(3)})`;
		ctx.fill();
	}
}

// ─── ANIMATION LOOP ─────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) {
			requestAnimationFrame(render);
			return;
		}
		now *= 0.001;
		const dt = lastTime ? Math.min(now - lastTime, 0.05) : 0.016;
		lastTime = now;

		update(dt);
		draw();

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// ─── MESSAGE HANDLER ─────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Nebula Clouds
 * Description: Soft, slowly drifting colored cloud formations using layered circles with very low
 *              opacity and large radii. Colors are deep purples, blues, and pinks.
 *              Mouse proximity causes nearby clouds to gently disperse.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let clouds = [];
let time = 0;

const CLOUD_COUNT = 45;
const MOUSE_RADIUS = 200;
const MOUSE_FORCE = 0.8;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// Nebula palette: deep purples, blues, pinks
const NEBULA_COLORS = [
	{ r: 80, g: 40, b: 160 }, // deep purple
	{ r: 40, g: 60, b: 180 }, // deep blue
	{ r: 160, g: 50, b: 120 }, // magenta-pink
	{ r: 60, g: 30, b: 140 }, // violet
	{ r: 100, g: 60, b: 200 }, // lavender
	{ r: 30, g: 80, b: 160 }, // royal blue
	{ r: 180, g: 60, b: 160 }, // hot pink
	{ r: 50, g: 50, b: 120 } // dark indigo
];

class Cloud {
	constructor() {
		this.reset(true);
	}

	reset(initial = false) {
		this.x = Math.random() * width;
		this.y = Math.random() * height;
		this.radius = 80 + Math.random() * 200;
		this.baseRadius = this.radius;
		this.vx = (Math.random() - 0.5) * 0.15;
		this.vy = (Math.random() - 0.5) * 0.1;
		this.color = NEBULA_COLORS[Math.floor(Math.random() * NEBULA_COLORS.length)];
		this.opacity = 0.015 + Math.random() * 0.03;
		this.phase = Math.random() * Math.PI * 2;
		this.pulseSpeed = 0.005 + Math.random() * 0.01;
		this.layers = 2 + Math.floor(Math.random() * 3); // 2-4 sub-layers
		// Dispersion offset from mouse interaction
		this.offsetX = 0;
		this.offsetY = 0;
	}

	update() {
		// Gentle drift
		this.x += this.vx;
		this.y += this.vy;

		// Breathing pulse
		this.radius = this.baseRadius + Math.sin(time * this.pulseSpeed + this.phase) * 15;

		// Wrap around edges with buffer
		const buffer = this.radius * 2;
		if (this.x < -buffer) this.x = width + buffer;
		if (this.x > width + buffer) this.x = -buffer;
		if (this.y < -buffer) this.y = height + buffer;
		if (this.y > height + buffer) this.y = -buffer;

		// Mouse dispersal
		const dx = this.x + this.offsetX - mouse.x;
		const dy = this.y + this.offsetY - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);

		if (dist < MOUSE_RADIUS && dist > 0) {
			const force = (1 - dist / MOUSE_RADIUS) * MOUSE_FORCE;
			this.offsetX += (dx / dist) * force;
			this.offsetY += (dy / dist) * force;
		}

		// Smoothly return offset to zero
		this.offsetX *= 0.97;
		this.offsetY *= 0.97;
	}

	draw() {
		const drawX = this.x + this.offsetX;
		const drawY = this.y + this.offsetY;
		const { r, g, b } = this.color;

		// Draw multiple concentric layers for soft cloud effect
		for (let i = this.layers; i >= 0; i--) {
			const layerRadius = this.radius * (0.4 + i * 0.25);
			const layerOpacity = this.opacity * (1 - i * 0.2);

			const gradient = ctx.createRadialGradient(drawX, drawY, 0, drawX, drawY, layerRadius);
			gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${layerOpacity})`);
			gradient.addColorStop(0.4, `rgba(${r}, ${g}, ${b}, ${layerOpacity * 0.6})`);
			gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);

			ctx.beginPath();
			ctx.arc(drawX, drawY, layerRadius, 0, Math.PI * 2);
			ctx.fillStyle = gradient;
			ctx.fill();
		}
	}
}

function initClouds() {
	clouds = [];
	for (let i = 0; i < CLOUD_COUNT; i++) {
		clouds.push(new Cloud());
	}
}

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time += 1;

		// Sort by radius for depth ordering (smaller = further back)
		clouds.sort((a, b) => a.baseRadius - b.baseRadius);

		for (const cloud of clouds) {
			cloud.update();
			cloud.draw();
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initClouds();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initClouds();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Nebula (WebGL)
 * Description: GPU-accelerated cosmic nebula using WebGL fragment shaders
 *   in a Worker. Demonstrates that Canvas FX scripts can use WebGL — not
 *   just the 2D canvas API. Renders multi-octave domain-warped fractal
 *   noise through a color palette, creating flowing organic nebula patterns
 *   that 2D canvas simply cannot produce at this quality/performance.
 *   Mouse position acts as a gravity lens distorting the nebula field.
 *
 *   This is the first Canvas FX script to use WebGL.
 *
 *   Showcases: WebGL in OffscreenCanvas Worker, GLSL shaders, mousemove
 */

/* ────────── CONFIGURABLE ────────── */
var SPEED           = 0.12;      // animation speed
var WARP_INTENSITY  = 1.4;       // domain warp strength (higher = more organic)
var NOISE_OCTAVES   = 6;         // FBM detail level (2-8, higher = finer detail)
var MOUSE_STRENGTH  = 0.12;     // mouse distortion intensity
var VIGNETTE        = 1.4;       // edge darkening (0 = none)
var BRIGHTNESS      = 1.1;       // overall brightness multiplier
var PALETTE_SPEED   = 0.08;      // color palette drift speed
/* ──────────────────────────────────── */

var canvas, gl, program;
var uTime, uResolution, uMouse, uConfig;
var startTime = 0;
var mouseNX = 0.5, mouseNY = 0.5; // normalized 0-1
var w = 0, h = 0;

setInterval(function() { self.postMessage({ type: 'heartbeat' }); }, 1000);

/* ── Shaders ── */
var VERT_SRC = [
    'attribute vec2 a_pos;',
    'void main() { gl_Position = vec4(a_pos, 0.0, 1.0); }'
].join('\n');

var FRAG_SRC = [
    'precision highp float;',
    '',
    'uniform float u_time;',
    'uniform vec2 u_resolution;',
    'uniform vec2 u_mouse;',
    'uniform vec4 u_config;', // x=warpIntensity, y=vignette, z=brightness, w=paletteSpeed
    '',
    '// ── Hash-based 3D noise ──',
    'float hash(vec3 p) {',
    '    p = fract(p * 0.3183099 + 0.1);',
    '    p *= 17.0;',
    '    return fract(p.x * p.y * p.z * (p.x + p.y + p.z));',
    '}',
    '',
    'float noise(vec3 x) {',
    '    vec3 i = floor(x);',
    '    vec3 f = fract(x);',
    '    f = f * f * (3.0 - 2.0 * f);',
    '    return mix(',
    '        mix(mix(hash(i), hash(i + vec3(1,0,0)), f.x),',
    '            mix(hash(i + vec3(0,1,0)), hash(i + vec3(1,1,0)), f.x), f.y),',
    '        mix(mix(hash(i + vec3(0,0,1)), hash(i + vec3(1,0,1)), f.x),',
    '            mix(hash(i + vec3(0,1,1)), hash(i + vec3(1,1,1)), f.x), f.y),',
    '        f.z);',
    '}',
    '',
    '// ── Fractal Brownian Motion ──',
    'float fbm(vec3 p) {',
    '    float f = 0.0, a = 0.5;',
    '    for (int i = 0; i < ' + NOISE_OCTAVES + '; i++) {',
    '        f += a * noise(p);',
    '        p = p * 2.01 + vec3(0.13, -0.27, 0.05);', // slight offset prevents axis alignment
    '        a *= 0.49;',
    '    }',
    '    return f;',
    '}',
    '',
    '// ── Iq color palette (a + b * cos(2π(c*t + d))) ──',
    'vec3 palette(float t) {',
    '    vec3 a = vec3(0.5, 0.5, 0.5);',
    '    vec3 b = vec3(0.5, 0.5, 0.5);',
    '    vec3 c = vec3(1.0, 1.0, 1.0);',
    '    vec3 d = vec3(0.263, 0.416, 0.557);', // deep space palette
    '    return a + b * cos(6.28318 * (c * t + d));',
    '}',
    '',
    'void main() {',
    '    vec2 uv = gl_FragCoord.xy / u_resolution;',
    '    float aspect = u_resolution.x / u_resolution.y;',
    '    vec2 p = (2.0 * gl_FragCoord.xy - u_resolution) / min(u_resolution.x, u_resolution.y);',
    '',
    '    float t = u_time;',
    '    float warp = u_config.x;',
    '',
    '    // Mouse gravity lens',
    '    vec2 mp = (2.0 * u_mouse * u_resolution - u_resolution) / min(u_resolution.x, u_resolution.y);',
    '    float md = length(p - mp);',
    '    p += (mp - p) * ' + MOUSE_STRENGTH.toFixed(3) + ' / (1.0 + md * md * 3.0);',
    '',
    '    // Domain warping — three passes for deep organic structure',
    '    vec3 q = vec3(p * 1.2, t);',
    '    float f1 = fbm(q);',
    '    float f2 = fbm(q + vec3(f1 * warp, f1 * warp * 0.7, 0.3));',
    '    float f3 = fbm(q + vec3(f2 * warp * 1.2, f2 * warp * 0.9, f1 * 0.4 + t * 0.3));',
    '',
    '    // Color from palette — drift over time',
    '    vec3 col = palette(f3 * 0.7 + t * u_config.w);',
    '',
    '    // Add subtle highlight veins',
    '    float vein = smoothstep(0.48, 0.52, f2) * 0.3;',
    '    col += vec3(vein * 0.6, vein * 0.8, vein);',
    '',
    '    // Brightness',
    '    col *= u_config.z;',
    '',
    '    // Depth fade toward edges',
    '    float fade = 1.0 - smoothstep(0.6, 2.2, length(p));',
    '    col *= mix(1.0, fade, 0.6);',
    '',
    '    // Vignette',
    '    float vig = 1.0 - dot(uv - 0.5, uv - 0.5) * u_config.y;',
    '    col *= max(vig, 0.0);',
    '',
    '    // Subtle film grain',
    '    float grain = hash(vec3(gl_FragCoord.xy, t * 100.0)) * 0.03;',
    '    col += grain;',
    '',
    '    gl_FragColor = vec4(col, 1.0);',
    '}'
].join('\n');

/* ── GL helpers ── */
function compileShader(type, src) {
    var s = gl.createShader(type);
    gl.shaderSource(s, src);
    gl.compileShader(s);
    if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) {
        var err = gl.getShaderInfoLog(s);
        gl.deleteShader(s);
        throw new Error('Shader compile: ' + err);
    }
    return s;
}

function initGL() {
    var vs = compileShader(gl.VERTEX_SHADER, VERT_SRC);
    var fs = compileShader(gl.FRAGMENT_SHADER, FRAG_SRC);

    program = gl.createProgram();
    gl.attachShader(program, vs);
    gl.attachShader(program, fs);
    gl.linkProgram(program);
    if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
        throw new Error('Program link: ' + gl.getProgramInfoLog(program));
    }
    gl.useProgram(program);

    // Fullscreen triangle (covers viewport with a single triangle — no quad seam)
    var buf = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, buf);
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1,-1, 3,-1, -1,3]), gl.STATIC_DRAW);

    var aPos = gl.getAttribLocation(program, 'a_pos');
    gl.enableVertexAttribArray(aPos);
    gl.vertexAttribPointer(aPos, 2, gl.FLOAT, false, 0, 0);

    // Uniform locations
    uTime = gl.getUniformLocation(program, 'u_time');
    uResolution = gl.getUniformLocation(program, 'u_resolution');
    uMouse = gl.getUniformLocation(program, 'u_mouse');
    uConfig = gl.getUniformLocation(program, 'u_config');

    startTime = performance.now() / 1000;
}

/* ── Render ── */
function render() {
    var t = (performance.now() / 1000 - startTime) * SPEED;

    gl.viewport(0, 0, w, h);
    gl.uniform1f(uTime, t);
    gl.uniform2f(uResolution, w, h);
    gl.uniform2f(uMouse, mouseNX, mouseNY);
    gl.uniform4f(uConfig, WARP_INTENSITY, VIGNETTE, BRIGHTNESS, PALETTE_SPEED);

    gl.drawArrays(gl.TRIANGLES, 0, 3);

    requestAnimationFrame(render);
}

/* ── Message handler ── */
self.onmessage = function(e) {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            w = e.data.width;
            h = e.data.height;
            canvas.width = w;
            canvas.height = h;

            // Try WebGL2 first, then WebGL1
            gl = canvas.getContext('webgl2');
            if (!gl) gl = canvas.getContext('webgl');
            if (!gl) {
                // Ultimate fallback: 2D message
                var ctx2d = canvas.getContext('2d');
                ctx2d.fillStyle = '#0a0a1a';
                ctx2d.fillRect(0, 0, w, h);
                ctx2d.fillStyle = '#ff4466';
                ctx2d.font = '16px monospace';
                ctx2d.textAlign = 'center';
                ctx2d.fillText('WebGL not available in this browser', w/2, h/2);
                return;
            }

            try {
                initGL();
                render();
            } catch(err) {
                // Shader compile error fallback
                var ctx2d = canvas.getContext('2d');
                if (ctx2d) {
                    ctx2d.fillStyle = '#0a0a1a';
                    ctx2d.fillRect(0, 0, w, h);
                    ctx2d.fillStyle = '#ff4466';
                    ctx2d.font = '14px monospace';
                    ctx2d.textAlign = 'center';
                    ctx2d.fillText('WebGL error: ' + err.message, w/2, h/2);
                }
            }
            break;

        case 'resize':
            w = e.data.width;
            h = e.data.height;
            canvas.width = w;
            canvas.height = h;
            break;

        case 'mousemove':
            mouseNX = e.data.x / w;
            mouseNY = 1.0 - (e.data.y / h); // flip Y for GL coordinates
            break;
    }
};

/**
 * Title: Neural Network
 * Description: Visualization of connected nodes in layers with pulses of light traveling
 *   along connections. Nodes glow when activated. The network slowly reorganizes.
 *   Mouse adds energy to the nearest node, triggering cascading activations.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

let layers = [];
let connections = [];
let pulses = [];

const LAYER_COUNT = 5;
const NODE_RADIUS = 4;
const MAX_PULSES = 80;
const REORGANIZE_SPEED = 0.002;

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initNetwork();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initNetwork();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function initNetwork() {
	layers = [];
	connections = [];
	pulses = [];

	// Create layers with varying node counts
	const nodeCounts = [];
	for (let l = 0; l < LAYER_COUNT; l++) {
		if (l === 0 || l === LAYER_COUNT - 1) {
			nodeCounts.push(3 + Math.floor(Math.random() * 3));
		} else {
			nodeCounts.push(5 + Math.floor(Math.random() * 5));
		}
	}

	const layerSpacing = width / (LAYER_COUNT + 1);

	for (let l = 0; l < LAYER_COUNT; l++) {
		const layer = [];
		const count = nodeCounts[l];
		const nodeSpacing = height / (count + 1);
		const baseX = layerSpacing * (l + 1);

		for (let n = 0; n < count; n++) {
			const baseY = nodeSpacing * (n + 1);
			layer.push({
				x: baseX,
				y: baseY,
				targetX: baseX + (Math.random() - 0.5) * 30,
				targetY: baseY + (Math.random() - 0.5) * 20,
				energy: 0, // 0-1 glow intensity
				layer: l,
				index: n,
				driftPhase: Math.random() * Math.PI * 2
			});
		}
		layers.push(layer);
	}

	// Create connections between adjacent layers (not fully connected — sparse)
	for (let l = 0; l < LAYER_COUNT - 1; l++) {
		const fromLayer = layers[l];
		const toLayer = layers[l + 1];

		for (const from of fromLayer) {
			// Connect to 1-3 nodes in the next layer
			const connectCount = 1 + Math.floor(Math.random() * Math.min(3, toLayer.length));
			const targets = shuffleArray([...toLayer]).slice(0, connectCount);

			for (const to of targets) {
				connections.push({
					from: from,
					to: to,
					weight: 0.3 + Math.random() * 0.7,
					opacity: 0.06 + Math.random() * 0.08
				});
			}
		}
	}
}

function shuffleArray(arr) {
	for (let i = arr.length - 1; i > 0; i--) {
		const j = Math.floor(Math.random() * (i + 1));
		[arr[i], arr[j]] = [arr[j], arr[i]];
	}
	return arr;
}

function spawnPulse(connection) {
	if (pulses.length >= MAX_PULSES) return;
	pulses.push({
		conn: connection,
		progress: 0,
		speed: 0.008 + Math.random() * 0.012,
		brightness: 0.4 + Math.random() * 0.6
	});
}

function startAnimation() {
	let lastMouseActivation = 0;
	let spontaneousTimer = 0;

	function render(time) {
		if (!ctx) return;

		ctx.clearRect(0, 0, width, height);

		// Slow reorganization — nodes drift toward new targets
		for (const layer of layers) {
			for (const node of layer) {
				// Gentle sine-based drift
				node.driftPhase += REORGANIZE_SPEED;
				const drift = Math.sin(node.driftPhase) * 15;
				const driftY = Math.cos(node.driftPhase * 0.7) * 10;

				node.x += (node.targetX + drift - node.x) * 0.01;
				node.y += (node.targetY + driftY - node.y) * 0.01;

				// Decay energy
				node.energy *= 0.97;
			}
		}

		// Mouse interaction — energize nearest node
		if (time - lastMouseActivation > 200) {
			let nearest = null;
			let nearestDist = Infinity;

			for (const layer of layers) {
				for (const node of layer) {
					const dx = node.x - mouse.x;
					const dy = node.y - mouse.y;
					const dist = dx * dx + dy * dy;
					if (dist < nearestDist) {
						nearestDist = dist;
						nearest = node;
					}
				}
			}

			if (nearest && nearestDist < 200 * 200) {
				nearest.energy = Math.min(1, nearest.energy + 0.5);
				// Fire pulses along outgoing connections
				for (const conn of connections) {
					if (conn.from === nearest && Math.random() < 0.6) {
						spawnPulse(conn);
					}
				}
				lastMouseActivation = time;
			}
		}

		// Spontaneous firing
		spontaneousTimer++;
		if (spontaneousTimer > 60) {
			spontaneousTimer = 0;
			// Pick a random input node to fire
			const inputLayer = layers[0];
			const node = inputLayer[Math.floor(Math.random() * inputLayer.length)];
			node.energy = Math.min(1, node.energy + 0.3);

			for (const conn of connections) {
				if (conn.from === node && Math.random() < 0.4) {
					spawnPulse(conn);
				}
			}
		}

		// Draw connections
		for (const conn of connections) {
			ctx.beginPath();
			ctx.moveTo(conn.from.x, conn.from.y);
			ctx.lineTo(conn.to.x, conn.to.y);

			// Brighter if either node is energized
			const energyBoost = Math.max(conn.from.energy, conn.to.energy) * 0.2;
			ctx.strokeStyle = `rgba(100, 160, 255, ${conn.opacity + energyBoost})`;
			ctx.lineWidth = 0.8 + conn.weight * 0.5;
			ctx.stroke();
		}

		// Update and draw pulses
		for (let i = pulses.length - 1; i >= 0; i--) {
			const p = pulses[i];
			p.progress += p.speed;

			if (p.progress >= 1) {
				// Pulse arrived — energize target node and cascade
				p.conn.to.energy = Math.min(1, p.conn.to.energy + 0.3 * p.brightness);

				// Cascade: fire from the target node (with diminishing probability)
				if (p.brightness > 0.2) {
					for (const conn of connections) {
						if (conn.from === p.conn.to && Math.random() < 0.35) {
							if (pulses.length < MAX_PULSES) {
								pulses.push({
									conn: conn,
									progress: 0,
									speed: 0.008 + Math.random() * 0.012,
									brightness: p.brightness * 0.7
								});
							}
						}
					}
				}

				pulses.splice(i, 1);
				continue;
			}

			// Interpolate position
			const px = p.conn.from.x + (p.conn.to.x - p.conn.from.x) * p.progress;
			const py = p.conn.from.y + (p.conn.to.y - p.conn.from.y) * p.progress;

			ctx.beginPath();
			ctx.arc(px, py, 2.5, 0, Math.PI * 2);
			ctx.fillStyle = `rgba(140, 200, 255, ${p.brightness * 0.7})`;
			ctx.shadowColor = `rgba(100, 180, 255, ${p.brightness * 0.5})`;
			ctx.shadowBlur = 8;
			ctx.fill();
			ctx.shadowBlur = 0;
		}

		// Draw nodes
		for (const layer of layers) {
			for (const node of layer) {
				const glow = node.energy;

				// Outer glow
				if (glow > 0.05) {
					ctx.beginPath();
					ctx.arc(node.x, node.y, NODE_RADIUS + 6, 0, Math.PI * 2);
					ctx.fillStyle = `rgba(100, 180, 255, ${glow * 0.15})`;
					ctx.fill();
				}

				// Node body
				ctx.beginPath();
				ctx.arc(node.x, node.y, NODE_RADIUS, 0, Math.PI * 2);
				const baseAlpha = 0.15 + glow * 0.6;
				ctx.fillStyle = `rgba(120, 180, 255, ${baseAlpha})`;
				ctx.fill();

				// Bright center when energized
				if (glow > 0.1) {
					ctx.beginPath();
					ctx.arc(node.x, node.y, NODE_RADIUS * 0.5, 0, Math.PI * 2);
					ctx.fillStyle = `rgba(200, 230, 255, ${glow * 0.5})`;
					ctx.shadowColor = `rgba(120, 200, 255, ${glow * 0.4})`;
					ctx.shadowBlur = 10;
					ctx.fill();
					ctx.shadowBlur = 0;
				}
			}
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Northern Lights Curtain
 * Description: Vertical curtains of shimmering aurora light that sway horizontally.
 *   Layered vertical bands with colors shifting between green, cyan, and magenta.
 *   They shimmer with varying brightness. Mouse position pushes curtains aside.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let curtains = [];
let shimmerPoints = [];

const NUM_CURTAINS = 8;
const SHIMMER_POINTS = 25;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class AuroraCurtain {
	constructor(index, total) {
		this.index = index;
		this.total = total;
		// Base X position spread across the screen
		this.baseX = 0;
		this.recalc();
		// Sway parameters
		this.swayPhase = Math.random() * Math.PI * 2;
		this.swaySpeed = 0.003 + Math.random() * 0.004;
		this.swayAmplitude = 30 + Math.random() * 50;
		// Secondary sway for organic movement
		this.sway2Phase = Math.random() * Math.PI * 2;
		this.sway2Speed = 0.007 + Math.random() * 0.005;
		this.sway2Amplitude = 10 + Math.random() * 20;
		// Color cycling
		this.colorPhase = (index / total) * Math.PI * 2;
		this.colorSpeed = 0.002 + Math.random() * 0.003;
		// Brightness
		this.baseBrightness = 0.06 + Math.random() * 0.06;
		this.brightness = this.baseBrightness;
		this.brightTarget = this.baseBrightness;
		this.shimmerTimer = Math.random() * 200;
		// Width of this curtain band
		this.bandWidth = 40 + Math.random() * 60;
		// Vertical extent — most curtains don't reach the bottom
		this.topY = 0;
		this.bottomFraction = 0.4 + Math.random() * 0.45; // extends 40-85% down
		// Number of control points for the curtain shape
		this.numPoints = 12 + Math.floor(Math.random() * 6);
	}

	recalc() {
		const spacing = (width || 800) / (this.total + 1);
		this.baseX = spacing * (this.index + 1);
	}

	getSwayOffset(y, t) {
		// Sway increases toward the bottom (curtain drapes from top)
		const yFactor = y / (height || 600);
		const sway1 = Math.sin(t * this.swaySpeed + this.swayPhase + y * 0.003) * this.swayAmplitude;
		const sway2 = Math.sin(t * this.sway2Speed + this.sway2Phase + y * 0.005) * this.sway2Amplitude;
		return (sway1 + sway2) * yFactor;
	}

	getMousePush(x, y) {
		const dx = x - mouse.x;
		const dy = y - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		const pushRadius = 200;
		if (dist < pushRadius && dist > 0) {
			const strength = 1 - dist / pushRadius;
			return (dx / dist) * strength * strength * 80;
		}
		return 0;
	}

	update(t) {
		// Shimmer — occasional brightness pulse
		this.shimmerTimer++;
		if (this.shimmerTimer > 100 + Math.random() * 200) {
			this.shimmerTimer = 0;
			this.brightTarget = this.baseBrightness + 0.04 + Math.random() * 0.08;
		}
		this.brightness += (this.brightTarget - this.brightness) * 0.02;
		this.brightTarget += (this.baseBrightness - this.brightTarget) * 0.005;
	}

	draw(ctx, t) {
		const bottomY = height * this.bottomFraction;
		const step = bottomY / this.numPoints;

		// Aurora colors: cycle between green (120), cyan (180), magenta (300)
		const colorT = t * this.colorSpeed + this.colorPhase;
		// Use sine to smoothly cycle through 3 hue anchors
		const hueBase = this.getAuroraHue(colorT);

		// Build left and right edges of the curtain
		const leftPoints = [];
		const rightPoints = [];

		for (let i = 0; i <= this.numPoints; i++) {
			const y = this.topY + i * step;
			const sway = this.getSwayOffset(y, t);
			const push = this.getMousePush(this.baseX + sway, y);
			const x = this.baseX + sway + push;

			// Width varies along height for organic shape
			const widthMod = 0.6 + 0.4 * Math.sin(i * 0.8 + t * 0.005);
			const halfW = (this.bandWidth * widthMod) / 2;

			leftPoints.push({ x: x - halfW, y });
			rightPoints.push({ x: x + halfW, y });
		}

		// Draw curtain as a filled shape with gradient
		ctx.beginPath();
		// Left edge (top to bottom)
		ctx.moveTo(leftPoints[0].x, leftPoints[0].y);
		for (let i = 1; i < leftPoints.length; i++) {
			const prev = leftPoints[i - 1];
			const curr = leftPoints[i];
			const cpx = (prev.x + curr.x) / 2;
			const cpy = (prev.y + curr.y) / 2;
			ctx.quadraticCurveTo(prev.x, prev.y, cpx, cpy);
		}
		ctx.lineTo(leftPoints[leftPoints.length - 1].x, leftPoints[leftPoints.length - 1].y);

		// Right edge (bottom to top)
		for (let i = rightPoints.length - 1; i >= 0; i--) {
			const curr = rightPoints[i];
			const next = i > 0 ? rightPoints[i - 1] : rightPoints[0];
			const cpx = (curr.x + next.x) / 2;
			const cpy = (curr.y + next.y) / 2;
			ctx.quadraticCurveTo(curr.x, curr.y, cpx, cpy);
		}
		ctx.closePath();

		// Vertical gradient — bright at top, fading out at bottom
		const midX = this.baseX + this.getSwayOffset(bottomY / 2, t);
		const grad = ctx.createLinearGradient(midX, this.topY, midX, bottomY);
		const alpha = this.brightness;
		const hue1 = hueBase;
		const hue2 = hueBase + 30;
		grad.addColorStop(0, `hsla(${hue1}, 80%, 65%, ${alpha * 1.2})`);
		grad.addColorStop(0.3, `hsla(${hue1}, 70%, 55%, ${alpha})`);
		grad.addColorStop(0.6, `hsla(${hue2}, 60%, 45%, ${alpha * 0.6})`);
		grad.addColorStop(1, `hsla(${hue2}, 50%, 35%, 0)`);

		ctx.fillStyle = grad;
		ctx.fill();

		// Inner glow line for shimmer
		ctx.beginPath();
		for (let i = 0; i <= this.numPoints; i++) {
			const y = this.topY + i * step;
			const sway = this.getSwayOffset(y, t);
			const push = this.getMousePush(this.baseX + sway, y);
			const x = this.baseX + sway + push;
			if (i === 0) {
				ctx.moveTo(x, y);
			} else {
				const prevY = this.topY + (i - 1) * step;
				const prevSway = this.getSwayOffset(prevY, t);
				const prevPush = this.getMousePush(this.baseX + prevSway, prevY);
				const prevX = this.baseX + prevSway + prevPush;
				ctx.quadraticCurveTo(prevX, prevY, (prevX + x) / 2, (prevY + y) / 2);
			}
		}
		ctx.strokeStyle = `hsla(${hue1}, 90%, 75%, ${alpha * 0.5})`;
		ctx.lineWidth = 1.5;
		ctx.stroke();
	}

	getAuroraHue(t) {
		// Cycle between green (120), cyan (180), magenta (300)
		const hues = [120, 180, 300, 120];
		const idx = ((t % (Math.PI * 2)) / (Math.PI * 2)) * 3;
		const i = Math.floor(idx) % 3;
		const frac = idx - Math.floor(idx);
		return hues[i] + (hues[i + 1] - hues[i]) * frac;
	}
}

class ShimmerPoint {
	constructor() {
		this.reset();
	}

	reset() {
		this.x = Math.random() * (width || 800);
		this.y = Math.random() * (height || 600) * 0.6;
		this.radius = 1 + Math.random() * 2;
		this.opacity = 0;
		this.maxOpacity = 0.05 + Math.random() * 0.1;
		this.fadeIn = true;
		this.speed = 0.002 + Math.random() * 0.004;
	}

	update() {
		if (this.fadeIn) {
			this.opacity += this.speed;
			if (this.opacity >= this.maxOpacity) {
				this.fadeIn = false;
			}
		} else {
			this.opacity -= this.speed;
			if (this.opacity <= 0) {
				this.reset();
			}
		}
	}

	draw(ctx) {
		if (this.opacity <= 0) return;
		const grad = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.radius * 4);
		grad.addColorStop(0, `rgba(200, 255, 220, ${this.opacity})`);
		grad.addColorStop(1, 'rgba(200, 255, 220, 0)');
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.radius * 4, 0, Math.PI * 2);
		ctx.fillStyle = grad;
		ctx.fill();
	}
}

function initCurtains() {
	curtains = [];
	for (let i = 0; i < NUM_CURTAINS; i++) {
		curtains.push(new AuroraCurtain(i, NUM_CURTAINS));
	}
	shimmerPoints = [];
	for (let i = 0; i < SHIMMER_POINTS; i++) {
		shimmerPoints.push(new ShimmerPoint());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initCurtains();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			for (const c of curtains) {
				c.recalc();
			}
			shimmerPoints.forEach((s) => s.reset());
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time++;

		// Draw curtains
		for (const curtain of curtains) {
			curtain.update(time);
			curtain.draw(ctx, time);
		}

		// Draw shimmer points (star-like sparkles in the aurora)
		for (const sp of shimmerPoints) {
			sp.update();
			sp.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Ocean Waves
 * Description: Layered horizontal wave patterns at different depths, creating an
 *   ocean surface viewed from below. Deep blues and teals with varying opacity.
 *   Mouse position creates a swell/disturbance in the nearest wave layer.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let layers = [];

const NUM_LAYERS = 5;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class WaveLayer {
	constructor(index, total) {
		// Depth: 0 = deepest/back, total-1 = shallowest/front
		this.depth = index / (total - 1); // 0..1
		this.yBase = 0;
		this.amplitude = 0;
		this.frequency = 0;
		this.speed = 0;
		this.phase = Math.random() * Math.PI * 2;
		this.secondaryFreq = 0;
		this.secondaryAmp = 0;
		this.recalc(index, total);
	}

	recalc(index, total) {
		// Position layers from top ~30% to bottom ~80% of screen
		const t = index / (total - 1);
		this.yBase = height * (0.25 + t * 0.55);
		this.amplitude = 15 + t * 25;
		this.frequency = 0.003 + (1 - t) * 0.004;
		this.speed = 0.008 + (1 - t) * 0.012;
		this.secondaryFreq = this.frequency * 2.3;
		this.secondaryAmp = this.amplitude * 0.3;
		// Color — deep layers are darker and more blue, shallow are lighter and teal
		const hue = 200 + t * 20; // 200 (deep blue) to 220 (teal-ish)
		const lightness = 15 + t * 20;
		const alpha = 0.08 + t * 0.12;
		this.color = `hsla(${hue}, 70%, ${lightness}%, ${alpha})`;
		this.highlightColor = `hsla(${hue - 10}, 60%, ${lightness + 15}%, ${alpha * 0.5})`;
	}

	getY(x, t, mouseInfluence) {
		// Primary wave
		let y =
			this.yBase + Math.sin(x * this.frequency + t * this.speed + this.phase) * this.amplitude;
		// Secondary harmonic
		y +=
			Math.sin(x * this.secondaryFreq + t * this.speed * 1.5 + this.phase * 2) * this.secondaryAmp;
		// Tertiary ripple for realism
		y += Math.sin(x * this.frequency * 4.7 + t * this.speed * 0.7) * this.amplitude * 0.08;
		// Mouse swell disturbance
		y += mouseInfluence;
		return y;
	}

	getMouseInfluence(x) {
		const dx = x - mouse.x;
		const dy = this.yBase - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		const influenceRadius = 250;
		if (dist < influenceRadius) {
			const strength = 1 - dist / influenceRadius;
			// Push wave away from mouse — creates a swell
			return -strength * strength * 40 * (1 - this.depth * 0.5);
		}
		return 0;
	}

	draw(ctx, t) {
		const step = 4; // pixel step for performance
		ctx.beginPath();
		ctx.moveTo(0, height);

		for (let x = 0; x <= width; x += step) {
			const mi = this.getMouseInfluence(x);
			const y = this.getY(x, t, mi);
			ctx.lineTo(x, y);
		}

		ctx.lineTo(width, height);
		ctx.closePath();
		ctx.fillStyle = this.color;
		ctx.fill();

		// Draw highlight line along the wave crest
		ctx.beginPath();
		for (let x = 0; x <= width; x += step) {
			const mi = this.getMouseInfluence(x);
			const y = this.getY(x, t, mi);
			if (x === 0) {
				ctx.moveTo(x, y);
			} else {
				ctx.lineTo(x, y);
			}
		}
		ctx.strokeStyle = this.highlightColor;
		ctx.lineWidth = 1.5;
		ctx.stroke();
	}
}

// Foam/bubble particles for surface detail
class Bubble {
	constructor() {
		this.reset();
	}

	reset() {
		this.x = Math.random() * (width || 800);
		this.y = (height || 600) * (0.2 + Math.random() * 0.6);
		this.radius = 0.5 + Math.random() * 1.5;
		this.opacity = 0.03 + Math.random() * 0.06;
		this.vx = (Math.random() - 0.5) * 0.3;
		this.vy = -0.1 - Math.random() * 0.3;
		this.life = 1;
		this.decay = 0.001 + Math.random() * 0.003;
	}

	update() {
		this.x += this.vx;
		this.y += this.vy;
		this.life -= this.decay;
		if (this.life <= 0 || this.y < 0) {
			this.reset();
		}
	}

	draw(ctx) {
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(150, 200, 220, ${this.opacity * this.life})`;
		ctx.fill();
	}
}

let bubbles = [];
const MAX_BUBBLES = 30;

function initLayers() {
	layers = [];
	for (let i = 0; i < NUM_LAYERS; i++) {
		layers.push(new WaveLayer(i, NUM_LAYERS));
	}
	bubbles = [];
	for (let i = 0; i < MAX_BUBBLES; i++) {
		bubbles.push(new Bubble());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initLayers();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			// Recalculate layer positions
			for (let i = 0; i < layers.length; i++) {
				layers[i].recalc(i, NUM_LAYERS);
			}
			bubbles.forEach((b) => b.reset());
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time++;

		// Draw layers back to front (deep first)
		for (const layer of layers) {
			layer.draw(ctx, time);
		}

		// Draw bubbles
		for (const b of bubbles) {
			b.update();
			b.draw(ctx);
		}

		// Subtle caustic light pattern overlay
		drawCaustics(time);

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

function drawCaustics(t) {
	// Very subtle shifting light patches
	const count = 6;
	for (let i = 0; i < count; i++) {
		const cx = width * (0.15 + 0.7 * (i / count)) + Math.sin(t * 0.003 + i * 1.5) * 80;
		const cy = height * 0.4 + Math.cos(t * 0.004 + i * 2.1) * 60;
		const r = 60 + Math.sin(t * 0.005 + i) * 20;
		const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, r);
		const alpha = 0.015 + 0.01 * Math.sin(t * 0.006 + i * 3);
		grad.addColorStop(0, `rgba(120, 200, 220, ${alpha})`);
		grad.addColorStop(1, 'rgba(120, 200, 220, 0)');
		ctx.beginPath();
		ctx.arc(cx, cy, r, 0, Math.PI * 2);
		ctx.fillStyle = grad;
		ctx.fill();
	}
}

/**
 * Title: Pixel Rain
 * Description: Pixel-art style rain with blocky, grid-snapped drops, optional
 *   splash particles, and glowing trails. Mouse creates pixel splash ripples.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Grid --
  pixelSize: 4,                             // Grid snap size in pixels (2-10)

  // -- Drops --
  dropCount: 180,                           // Number of active rain drops (50-500)
  fallSpeed: 3.5,                           // Base fall speed in pixels per frame (1-10)
  fallSpeedVariance: 1.5,                   // Random speed variance added per drop (0-5)
  dropLength: 4,                            // Drop trail length in grid cells (1-10)

  // -- Colors --
  colorPalette: [                           // Array of drop colors — picked randomly
    'rgba(80, 180, 255, 0.9)',              //   Light blue
    'rgba(100, 200, 255, 0.7)',             //   Cyan-ish
    'rgba(60, 140, 220, 0.8)',              //   Steel blue
    'rgba(120, 220, 255, 0.6)',             //   Pale cyan
  ],

  // -- Trail --
  trailFadeSpeed: 0.88,                     // Per-frame opacity retention for trails (0.8-0.98)

  // -- Wind --
  windAngle: 5,                             // Wind slant in degrees (0=straight, -30 to 30)

  // -- Splash --
  splashEnabled: true,                      // Enable splash particles when drops hit bottom
  splashRadius: 3,                          // Splash particle spread in grid cells (1-8)
  splashParticleCount: 4,                   // Number of splash particles per drop (1-8)

  // -- Glow --
  backgroundGlowEnabled: true,              // Subtle ambient glow behind rain
  glowColor: 'rgba(60, 160, 255, 0.015)',   // Ambient glow tint color
  glowRadius: 60,                           // Glow circle radius around drops (20-100)

  // -- Mouse --
  mouseRippleRadius: 100,                   // Mouse splash ripple radius in px
  mouseRippleIntensity: 6,                  // How many splash particles the mouse generates (1-15)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let drops = [];
let splashes = [];
let trailCanvas, trailCtx;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initTrailBuffer();
      initDrops();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initTrailBuffer();
      initDrops();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      spawnMouseRipple();
      break;
  }
};

function initTrailBuffer() {
  trailCanvas = new OffscreenCanvas(width, height);
  trailCtx = trailCanvas.getContext('2d');
}

function snap(val) {
  return Math.floor(val / CONFIG.pixelSize) * CONFIG.pixelSize;
}

function randomColor() {
  const palette = CONFIG.colorPalette;
  return palette[Math.floor(Math.random() * palette.length)];
}

function initDrops() {
  drops = [];
  for (let i = 0; i < CONFIG.dropCount; i++) {
    drops.push(createDrop(true));
  }
}

function createDrop(randomY) {
  const windRad = (CONFIG.windAngle * Math.PI) / 180;
  return {
    x: snap(Math.random() * width),
    y: randomY ? snap(Math.random() * height) : snap(-CONFIG.pixelSize * CONFIG.dropLength),
    speed: CONFIG.fallSpeed + Math.random() * CONFIG.fallSpeedVariance,
    color: randomColor(),
    windDx: Math.tan(windRad),
  };
}

function spawnMouseRipple() {
  if (!CONFIG.splashEnabled) return;
  if (mouse.x < 0 || mouse.y < 0) return;

  for (let i = 0; i < CONFIG.mouseRippleIntensity; i++) {
    const angle = Math.random() * Math.PI * 2;
    const speed = 0.5 + Math.random() * 2;
    splashes.push({
      x: snap(mouse.x),
      y: snap(mouse.y),
      vx: Math.cos(angle) * speed * CONFIG.pixelSize,
      vy: Math.sin(angle) * speed * CONFIG.pixelSize - 1,
      life: 1,
      decay: 0.03 + Math.random() * 0.04,
      color: randomColor(),
    });
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;

    // Fade the trail buffer
    trailCtx.globalAlpha = CONFIG.trailFadeSpeed;
    trailCtx.globalCompositeOperation = 'source-over';
    trailCtx.fillStyle = 'rgba(0, 0, 0, 0.1)';
    // Use destination-in to fade existing content
    trailCtx.globalCompositeOperation = 'destination-in';
    trailCtx.fillStyle = `rgba(0, 0, 0, ${CONFIG.trailFadeSpeed})`;
    trailCtx.fillRect(0, 0, width, height);
    trailCtx.globalCompositeOperation = 'source-over';
    trailCtx.globalAlpha = 1;

    // Update and draw drops onto trail buffer
    const ps = CONFIG.pixelSize;
    for (let i = 0; i < drops.length; i++) {
      const d = drops[i];

      // Draw drop pixel column
      for (let j = 0; j < CONFIG.dropLength; j++) {
        const py = d.y - j * ps;
        if (py < 0 || py >= height) continue;
        const alpha = 1 - j / CONFIG.dropLength;
        trailCtx.globalAlpha = alpha;
        trailCtx.fillStyle = d.color;
        trailCtx.fillRect(snap(d.x), snap(py), ps, ps);
      }
      trailCtx.globalAlpha = 1;

      // Background glow
      if (CONFIG.backgroundGlowEnabled) {
        trailCtx.save();
        trailCtx.globalAlpha = 0.02;
        trailCtx.fillStyle = CONFIG.glowColor;
        trailCtx.beginPath();
        trailCtx.arc(d.x + ps / 2, d.y + ps / 2, CONFIG.glowRadius, 0, Math.PI * 2);
        trailCtx.fill();
        trailCtx.restore();
      }

      // Move
      d.y += d.speed * ps * 0.25;
      d.x += d.windDx * d.speed * 0.5;

      // Reset if off screen
      if (d.y > height + ps * CONFIG.dropLength) {
        if (CONFIG.splashEnabled) {
          spawnSplash(d.x, height);
        }
        Object.assign(d, createDrop(false));
      }
      if (d.x < -ps * 5 || d.x > width + ps * 5) {
        Object.assign(d, createDrop(false));
      }
    }

    // Update splashes
    for (let i = splashes.length - 1; i >= 0; i--) {
      const s = splashes[i];
      s.x += s.vx;
      s.y += s.vy;
      s.vy += 0.15 * ps * 0.25; // Gravity
      s.life -= s.decay;

      if (s.life <= 0) {
        splashes.splice(i, 1);
        continue;
      }

      trailCtx.globalAlpha = s.life;
      trailCtx.fillStyle = s.color;
      trailCtx.fillRect(snap(s.x), snap(s.y), ps, ps);
    }
    trailCtx.globalAlpha = 1;

    // Composite trail buffer to main canvas
    ctx.clearRect(0, 0, width, height);
    ctx.drawImage(trailCanvas, 0, 0);

    requestAnimationFrame(render);
  }

  requestAnimationFrame(render);
}

function spawnSplash(x, y) {
  for (let i = 0; i < CONFIG.splashParticleCount; i++) {
    const angle = -Math.PI * (0.15 + Math.random() * 0.7);
    const speed = 0.5 + Math.random() * CONFIG.splashRadius;
    const ps = CONFIG.pixelSize;
    splashes.push({
      x: snap(x),
      y: snap(y - ps),
      vx: Math.cos(angle) * speed * ps * 0.5,
      vy: Math.sin(angle) * speed * ps * 0.5,
      life: 1,
      decay: 0.04 + Math.random() * 0.05,
      color: randomColor(),
    });
  }
}

/**
 * Title: Quantum Foam
 * Description: A dense field of 2500 particles that bloom and fade across the
 *   full color spectrum, evoking quantum vacuum fluctuations. Particles spawn at
 *   random positions, grow outward, and dissolve into transparency.
 */
// QuantumFoam – transparency-optimized
// ------------------------------------------------------------------
// CONFIGURATION CONSTANTS
// ------------------------------------------------------------------
const PARTICLE_COUNT   = 2500; 
const MIN_RADIUS       = 0.5;  
const MAX_RADIUS       = 2;    
const GROWTH_SPEED     = 1.003;
const MIN_LIFE_DECAY   = 0.01; 
const MAX_LIFE_DECAY   = 0.02; 
const TRAIL_OPACITY    = 0.1;  // Controls how fast trails erase to transparency
const HUE_RANGE        = 360;   
const SATURATION       = '80%';
const LIGHTNESS        = '60%';
// ------------------------------------------------------------------

let c, ctx, w, h, foam = [];

self.onmessage = e => {
  if (e.data.type === 'init') {
    c = e.data.canvas;
    ctx = c.getContext('2d');
    w = c.width = e.data.width;
    h = c.height = e.data.height;

    foam = Array.from({ length: PARTICLE_COUNT }, _ => ({
      x: Math.random() * w,
      y: Math.random() * h,
      r: Math.random() * (MAX_RADIUS - MIN_RADIUS) + MIN_RADIUS,
      life: 1,
      decay: Math.random() * (MAX_LIFE_DECAY - MIN_LIFE_DECAY) + MIN_LIFE_DECAY,
      hue: Math.random() * HUE_RANGE
    }));
    animate();
  }

  if (e.data.type === 'resize') {
    w = c.width = e.data.width;
    h = c.height = e.data.height;
  }
};

function resetParticle(f) {
  f.x = Math.random() * w;
  f.y = Math.random() * h;
  f.r = MIN_RADIUS;
  f.life = 1;
  f.decay = Math.random() * (MAX_LIFE_DECAY - MIN_LIFE_DECAY) + MIN_LIFE_DECAY;
  f.hue = Math.random() * HUE_RANGE;
}

function animate() {
  // 1. Erase a portion of the previous frame to transparency
  ctx.globalCompositeOperation = 'destination-out';
  ctx.fillStyle = `rgba(0,0,0,${TRAIL_OPACITY})`;
  ctx.fillRect(0, 0, w, h);

  // 2. Switch back to normal drawing mode for particles
  ctx.globalCompositeOperation = 'source-over';

  for (let i = 0; i < foam.length; i++) {
    const f = foam[i];
    f.life -= f.decay;
    f.r *= GROWTH_SPEED;

    if (f.life <= 0) {
      resetParticle(f);
    }

    ctx.beginPath();
    ctx.arc(f.x, f.y, f.r, 0, Math.PI * 2);
    ctx.fillStyle = `hsla(${f.hue},${SATURATION},${LIGHTNESS},${f.life})`;
    ctx.fill();
  }

  requestAnimationFrame(animate);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Quantum Particle Tunnel
 * Description: A mesmerizing particle system that simulates quantum tunneling with probabilistic paths, 
 *              featuring real-time mouse interaction, particle trails, and dynamic color shifts
 */

let canvas, ctx, width, height;
let mouse = { x: -1000, y: -1000 };
let particles = [];
let time = 0;

// Quantum tunneling probability matrix
const tunnelMatrix = [
    [0.1, 0.3, 0.6],
    [0.2, 0.5, 0.3],
    [0.4, 0.1, 0.5]
];

class Particle {
    constructor(x, y) {
        this.x = x;
        this.y = y;
        this.vx = (Math.random() - 0.5) * 2;
        this.vy = (Math.random() - 0.5) * 2;
        this.size = Math.random() * 3 + 1;
        this.color = `hsl(${Math.random() * 360}, 100%, 60%)`;
        this.life = 100;
        this.tunnelProbability = Math.random();
        this.quantumState = Math.floor(Math.random() * 3);
    }

    update() {
        // Quantum tunneling effect
        if (Math.random() < 0.02 * this.tunnelProbability) {
            this.x = Math.random() * width;
            this.y = Math.random() * height;
        }

        // Mouse interaction with quantum probability
        const dx = mouse.x - this.x;
        const dy = mouse.y - this.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance < 100) {
            const force = (100 - distance) / 100;
            this.vx += dx * force * 0.01;
            this.vy += dy * force * 0.01;
        }

        // Apply velocity
        this.x += this.vx;
        this.y += this.vy;

        // Boundary check with quantum tunneling
        if (this.x < 0) this.x = width;
        if (this.x > width) this.x = 0;
        if (this.y < 0) this.y = height;
        if (this.y > height) this.y = 0;

        // Dampening
        this.vx *= 0.98;
        this.vy *= 0.98;

        // Life cycle
        this.life--;
    }

    draw() {
        ctx.globalCompositeOperation = 'lighter';
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = this.color;
        ctx.fill();

        // Quantum glow effect
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size * 2, 0, Math.PI * 2);
        ctx.fillStyle = this.color.replace('60%', '80%').replace('100%', '40%');
        ctx.globalAlpha = 0.3;
        ctx.fill();
        ctx.globalAlpha = 1;
    }
}

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            render();
            break;
        case 'resize':
            resize(e.data.width, e.data.height);
            break;
        case 'mousemove':
            mouse.x = e.data.x;
            mouse.y = e.data.y;
            break;
    }
};

function resize(w, h) {
    width = w; 
    height = h;
    if (canvas) { 
        canvas.width = width; 
        canvas.height = height; 
    }

    // Reset particles on resize
    particles = [];
    for (let i = 0; i < 150; i++) {
        particles.push(new Particle(
            Math.random() * width,
            Math.random() * height
        ));
    }
}

function render() {
    if (!ctx) return;

    // Quantum background with transparency
    ctx.globalCompositeOperation = 'destination-out';
    ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
    ctx.fillRect(0, 0, width, height);
    ctx.globalCompositeOperation = 'source-over';

    // Quantum field visualization
    time += 0.01;
    const fieldSize = 50;
    for (let x = 0; x < width; x += fieldSize) {
        for (let y = 0; y < height; y += fieldSize) {
            const value = Math.sin(x * 0.01 + time) * Math.cos(y * 0.01 + time);
            const alpha = Math.abs(value) * 0.1;

            ctx.globalAlpha = alpha;
            ctx.fillStyle = `hsl(${(time * 20 + x + y) % 360}, 100%, 50%)`;
            ctx.fillRect(x, y, fieldSize, fieldSize);
        }
    }
    ctx.globalAlpha = 1;

    // Update and draw particles
    for (let i = 0; i < particles.length; i++) {
        particles[i].update();
        particles[i].draw();

        // Remove dead particles
        if (particles[i].life <= 0) {
            particles[i] = new Particle(
                Math.random() * width,
                Math.random() * height
            );
        }
    }

    requestAnimationFrame(render);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Rain on Glass
 * Description: Raindrops falling with realistic physics — acceleration, subtle streaks,
 *   occasional pausing and merging. Larger drops fall slower. Mouse position creates
 *   a wind effect that angles the rain.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let drops = [];
let streaks = [];

const MAX_DROPS = 180;
const MAX_STREAKS = 40;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class Raindrop {
	constructor() {
		this.reset(true);
	}

	reset(randomY = false) {
		this.x = Math.random() * width;
		this.y = randomY ? Math.random() * height : -10 - Math.random() * 60;
		this.radius = 1 + Math.random() * 2.5;
		this.vy = 0.5 + Math.random() * 1.5;
		this.vx = 0;
		this.acceleration = 0.02 + Math.random() * 0.04;
		this.maxSpeed = 3 + Math.random() * 4;
		this.opacity = 0.15 + Math.random() * 0.25;
		this.paused = false;
		this.pauseTimer = 0;
		this.pauseThreshold = 200 + Math.random() * 600;
		this.streakLength = 0;
		// Larger drops are slower
		if (this.radius > 2) {
			this.maxSpeed *= 0.6;
			this.acceleration *= 0.7;
			this.opacity += 0.05;
		}
	}

	update(windX) {
		// Chance to pause briefly (simulates surface tension on glass)
		this.pauseTimer++;
		if (!this.paused && this.pauseTimer > this.pauseThreshold && Math.random() < 0.003) {
			this.paused = true;
			this.pauseTimer = 0;
			this.pauseThreshold = 40 + Math.random() * 120;
		}
		if (this.paused) {
			this.pauseTimer++;
			if (this.pauseTimer > this.pauseThreshold) {
				this.paused = false;
				this.pauseTimer = 0;
				this.pauseThreshold = 200 + Math.random() * 600;
			}
			// Even when paused, slight wind drift
			this.x += windX * 0.1;
			this.streakLength *= 0.9;
			return;
		}

		// Accelerate
		this.vy = Math.min(this.vy + this.acceleration, this.maxSpeed);
		this.vx += (windX - this.vx) * 0.02;

		this.x += this.vx;
		this.y += this.vy;

		// Streak length proportional to speed
		this.streakLength = this.vy * 3;

		// Off-screen reset
		if (this.y > height + 20 || this.x < -20 || this.x > width + 20) {
			this.reset(false);
		}
	}

	draw(ctx) {
		// Draw streak behind the drop
		if (this.streakLength > 1) {
			ctx.beginPath();
			ctx.moveTo(this.x, this.y);
			ctx.lineTo(this.x - this.vx * 2, this.y - this.streakLength);
			ctx.strokeStyle = `rgba(180, 210, 240, ${this.opacity * 0.3})`;
			ctx.lineWidth = this.radius * 0.5;
			ctx.stroke();
		}

		// Draw the drop itself — slightly elongated when moving fast
		ctx.beginPath();
		const stretch = 1 + this.vy * 0.08;
		ctx.save();
		ctx.translate(this.x, this.y);
		ctx.scale(1, stretch);
		ctx.arc(0, 0, this.radius, 0, Math.PI * 2);
		ctx.restore();
		ctx.fillStyle = `rgba(180, 210, 240, ${this.opacity})`;
		ctx.fill();

		// Tiny highlight on top of drop for glass refraction look
		ctx.beginPath();
		ctx.arc(
			this.x - this.radius * 0.3,
			this.y - this.radius * 0.3,
			this.radius * 0.35,
			0,
			Math.PI * 2
		);
		ctx.fillStyle = `rgba(220, 240, 255, ${this.opacity * 0.5})`;
		ctx.fill();
	}
}

// Residual streak left behind by fast drops
class Streak {
	constructor(x, y, len) {
		this.x = x;
		this.y = y;
		this.length = len;
		this.opacity = 0.08;
		this.life = 1;
		this.decay = 0.003 + Math.random() * 0.005;
	}

	update() {
		this.life -= this.decay;
		this.opacity = 0.08 * this.life;
	}

	draw(ctx) {
		if (this.life <= 0) return;
		ctx.beginPath();
		ctx.moveTo(this.x, this.y);
		ctx.lineTo(this.x, this.y + this.length);
		ctx.strokeStyle = `rgba(180, 210, 240, ${this.opacity})`;
		ctx.lineWidth = 0.5;
		ctx.stroke();
	}
}

function initDrops() {
	drops = [];
	streaks = [];
	for (let i = 0; i < MAX_DROPS; i++) {
		drops.push(new Raindrop());
	}
}

function getWind() {
	// Wind based on mouse X position relative to center
	const centerX = width / 2;
	const dx = mouse.x - centerX;
	// Normalize to -1..1, scale for effect
	return (dx / centerX) * 1.5;
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initDrops();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initDrops();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		const wind = getWind();

		// Check for merging — nearby drops absorb smaller ones
		for (let i = 0; i < drops.length; i++) {
			for (let j = i + 1; j < drops.length; j++) {
				const dx = drops[i].x - drops[j].x;
				const dy = drops[i].y - drops[j].y;
				const dist = Math.sqrt(dx * dx + dy * dy);
				const mergeThresh = drops[i].radius + drops[j].radius;
				if (dist < mergeThresh) {
					// Merge: bigger drop absorbs smaller
					if (drops[i].radius >= drops[j].radius) {
						drops[i].radius = Math.min(drops[i].radius + drops[j].radius * 0.3, 4);
						drops[i].vy = Math.max(drops[i].vy, drops[j].vy);
						drops[j].reset(false);
					} else {
						drops[j].radius = Math.min(drops[j].radius + drops[i].radius * 0.3, 4);
						drops[j].vy = Math.max(drops[i].vy, drops[j].vy);
						drops[i].reset(false);
					}
					break;
				}
			}
		}

		// Occasional residual streaks
		if (Math.random() < 0.02 && streaks.length < MAX_STREAKS) {
			const d = drops[Math.floor(Math.random() * drops.length)];
			if (d.vy > 3) {
				streaks.push(new Streak(d.x, d.y, d.streakLength * 2));
			}
		}

		// Update and draw streaks
		for (let i = streaks.length - 1; i >= 0; i--) {
			streaks[i].update();
			streaks[i].draw(ctx);
			if (streaks[i].life <= 0) {
				streaks.splice(i, 1);
			}
		}

		// Update and draw drops
		for (const drop of drops) {
			drop.update(wind);
			drop.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Rainbow Sparkle Trail
 * Description: A magical rainbow sparkle trail that follows your mouse! Every
 *   movement creates a burst of colorful, glittery star-shaped particles that
 *   twirl, shrink, and fade. The faster you move, the more sparkles appear.
 *   Perfect for little ones who love chasing magic around the screen.
 */

/* ---------- CONFIGURABLE VARIABLES ---------- */
const MAX_SPARKLES      = 600;    // max particles alive at once
const SPAWN_RATE        = 8;      // sparkles spawned per frame while moving
const GRAVITY           = 0.04;   // gentle downward pull
const SPARKLE_SIZE_MIN  = 3;      // minimum star size
const SPARKLE_SIZE_MAX  = 10;     // maximum star size
const SPARKLE_LIFETIME  = 90;     // frames before a sparkle fades out
const SPIN_SPEED        = 0.08;   // rotation speed of star shapes
const SPREAD            = 40;     // pixel radius of spawn spread from cursor
const DRIFT_SPEED       = 0.6;    // lateral drift of particles
const RAINBOW_SPEED     = 3;      // how fast the hue cycles (degrees per frame)
/* --------------------------------------------- */

let canvas, ctx, w, h;
let sparkles = [];
let mouse = { x: -999, y: -999, px: -999, py: -999 };
let hueOffset = 0;
let time = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

class Sparkle {
	constructor(x, y, hue) {
		this.x = x + (Math.random() - 0.5) * SPREAD;
		this.y = y + (Math.random() - 0.5) * SPREAD;
		this.vx = (Math.random() - 0.5) * DRIFT_SPEED * 2;
		this.vy = -(Math.random() * 1.5 + 0.5);
		this.size = SPARKLE_SIZE_MIN + Math.random() * (SPARKLE_SIZE_MAX - SPARKLE_SIZE_MIN);
		this.rotation = Math.random() * Math.PI * 2;
		this.spinDir = Math.random() > 0.5 ? 1 : -1;
		this.hue = hue + (Math.random() - 0.5) * 30;
		this.life = SPARKLE_LIFETIME;
		this.maxLife = SPARKLE_LIFETIME;
		this.points = Math.random() > 0.5 ? 5 : 4; // 4 or 5 pointed stars
	}

	update() {
		this.life--;
		this.vy += GRAVITY;
		this.vx *= 0.99;
		this.x += this.vx;
		this.y += this.vy;
		this.rotation += SPIN_SPEED * this.spinDir;
		return this.life > 0;
	}

	draw(ctx) {
		const progress = 1 - this.life / this.maxLife;
		const alpha = Math.max(0, 1 - progress * progress);
		const scale = this.size * (1 - progress * 0.6);
		if (scale < 0.5) return;

		ctx.save();
		ctx.translate(this.x, this.y);
		ctx.rotate(this.rotation);
		ctx.globalAlpha = alpha;

		// Outer glow
		ctx.shadowColor = `hsl(${this.hue}, 100%, 70%)`;
		ctx.shadowBlur = scale * 3;

		// Draw star shape
		ctx.beginPath();
		const pts = this.points;
		for (let i = 0; i < pts * 2; i++) {
			const r = i % 2 === 0 ? scale : scale * 0.4;
			const angle = (i * Math.PI) / pts - Math.PI / 2;
			if (i === 0) ctx.moveTo(Math.cos(angle) * r, Math.sin(angle) * r);
			else ctx.lineTo(Math.cos(angle) * r, Math.sin(angle) * r);
		}
		ctx.closePath();
		ctx.fillStyle = `hsl(${this.hue}, 100%, ${70 + progress * 20}%)`;
		ctx.fill();

		ctx.shadowBlur = 0;
		ctx.globalAlpha = 1;
		ctx.restore();
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			startAnimation();
			break;
		case 'resize':
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			break;
		case 'mousemove':
			mouse.px = mouse.x;
			mouse.py = mouse.y;
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		time++;
		hueOffset = (hueOffset + RAINBOW_SPEED) % 360;

		// Fade to black with slight trail
		ctx.fillStyle = 'rgba(0, 0, 0, 0.12)';
		ctx.fillRect(0, 0, w, h);

		// Spawn sparkles if mouse is moving
		const dx = mouse.x - mouse.px;
		const dy = mouse.y - mouse.py;
		const speed = Math.sqrt(dx * dx + dy * dy);

		if (speed > 1 && mouse.x > 0 && mouse.y > 0) {
			const count = Math.min(SPAWN_RATE, Math.floor(speed / 2) + 2);
			for (let i = 0; i < count && sparkles.length < MAX_SPARKLES; i++) {
				const hue = (hueOffset + i * (360 / count)) % 360;
				sparkles.push(new Sparkle(mouse.x, mouse.y, hue));
			}
		}

		// Also spawn a gentle ambient sparkle occasionally
		if (time % 6 === 0 && sparkles.length < MAX_SPARKLES) {
			sparkles.push(new Sparkle(
				Math.random() * w,
				Math.random() * h,
				hueOffset + Math.random() * 120
			));
		}

		// Update and draw
		sparkles = sparkles.filter(s => s.update());
		for (const s of sparkles) {
			s.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Retro Sun
 * Description: Synthwave sunset with a glowing semi-circle sun, animated horizontal
 *   stripe cutouts, twinkling stars, and a rich gradient sky. Mouse proximity
 *   intensifies the sun's glow.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Sun --
  sunColorTop: '#ff6ec7',                 // Top gradient color of the sun
  sunColorBottom: '#ffb347',              // Bottom gradient color of the sun
  sunRadius: 120,                         // Sun radius in pixels
  sunPositionY: 0.55,                     // Sun vertical position (0=top, 1=bottom)
  glowIntensity: 1.2,                     // Base glow brightness (0-3)
  glowPulseSpeed: 0.8,                    // Glow pulse animation speed (0-5)

  // -- Stripes --
  stripeCount: 8,                         // Number of horizontal stripe cutouts
  stripeSpacing: 6,                       // Spacing between stripes in pixels
  stripeWidth: 4,                         // Width of each stripe in pixels
  stripeScrollSpeed: 0.3,                 // Speed stripes scroll upward

  // -- Horizon --
  horizonEnabled: true,                   // Show a horizon line
  horizonColor: '#ff6ec7',                // Horizon line color

  // -- Background --
  bgGradientTop: '#0a001a',              // Sky gradient top color (deep purple/black)
  bgGradientBottom: '#1a0033',           // Sky gradient bottom color

  // -- Stars --
  starCount: 80,                          // Number of twinkling stars
  starColor: 'rgba(255, 255, 255, 0.8)', // Star color

  // -- Mouse --
  mouseGlowRadius: 300,                  // Mouse influence radius for glow boost
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let stars = [];
let time = 0;
let stripeOffset = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function hexToRgb(hex) {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return { r, g, b };
}

function initStars() {
  stars = [];
  const sunY = height * CONFIG.sunPositionY;
  for (let i = 0; i < CONFIG.starCount; i++) {
    stars.push({
      x: Math.random() * width,
      y: Math.random() * sunY * 0.9,
      size: Math.random() * 1.8 + 0.5,
      twinkleSpeed: Math.random() * 0.03 + 0.01,
      twinkleOffset: Math.random() * Math.PI * 2,
    });
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 0.016;
    stripeOffset = (stripeOffset + CONFIG.stripeScrollSpeed) % (CONFIG.stripeSpacing + CONFIG.stripeWidth);

    const sunY = height * CONFIG.sunPositionY;
    const sunX = width / 2;

    // -- Background gradient --
    const bgGrad = ctx.createLinearGradient(0, 0, 0, height);
    bgGrad.addColorStop(0, CONFIG.bgGradientTop);
    bgGrad.addColorStop(0.6, CONFIG.bgGradientBottom);
    bgGrad.addColorStop(1, '#000000');
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, width, height);

    // -- Stars --
    for (const star of stars) {
      const twinkle = 0.3 + 0.7 * Math.abs(Math.sin(time * star.twinkleSpeed * 60 + star.twinkleOffset));
      ctx.beginPath();
      ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
      ctx.fillStyle = CONFIG.starColor.replace(/[\d.]+\)$/, (twinkle * 0.8).toFixed(2) + ')');
      ctx.fill();
    }

    // -- Sun glow (behind sun) --
    const dx = mouse.x - sunX;
    const dy = mouse.y - sunY;
    const mouseDist = Math.sqrt(dx * dx + dy * dy);
    const mouseBoost = Math.max(0, 1 - mouseDist / CONFIG.mouseGlowRadius) * 0.6;
    const pulse = Math.sin(time * CONFIG.glowPulseSpeed) * 0.15 + 0.85;
    const glowAlpha = CONFIG.glowIntensity * pulse * 0.15 + mouseBoost * 0.1;

    const topRgb = hexToRgb(CONFIG.sunColorTop);
    for (let i = 3; i >= 1; i--) {
      const r = CONFIG.sunRadius * (1 + i * 0.8);
      const glow = ctx.createRadialGradient(sunX, sunY, CONFIG.sunRadius * 0.5, sunX, sunY, r);
      glow.addColorStop(0, `rgba(${topRgb.r}, ${topRgb.g}, ${topRgb.b}, ${glowAlpha * (0.4 / i)})`);
      glow.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.fillStyle = glow;
      ctx.fillRect(0, 0, width, height);
    }

    // -- Sun body (semi-circle above horizon) --
    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, width, sunY);
    ctx.clip();

    const sunGrad = ctx.createLinearGradient(sunX, sunY - CONFIG.sunRadius, sunX, sunY + CONFIG.sunRadius * 0.3);
    sunGrad.addColorStop(0, CONFIG.sunColorTop);
    sunGrad.addColorStop(1, CONFIG.sunColorBottom);
    ctx.fillStyle = sunGrad;
    ctx.beginPath();
    ctx.arc(sunX, sunY, CONFIG.sunRadius, 0, Math.PI * 2);
    ctx.fill();

    // -- Stripe cutouts on sun --
    ctx.globalCompositeOperation = 'destination-out';
    const stripeStart = sunY - CONFIG.sunRadius;
    const stripeEnd = sunY;
    for (let y = stripeStart + stripeOffset; y < stripeEnd; y += CONFIG.stripeSpacing + CONFIG.stripeWidth) {
      if (y > stripeStart + CONFIG.sunRadius * 0.3) {
        ctx.fillStyle = 'rgba(0, 0, 0, 1)';
        ctx.fillRect(sunX - CONFIG.sunRadius - 10, y, CONFIG.sunRadius * 2 + 20, CONFIG.stripeWidth);
      }
    }
    ctx.globalCompositeOperation = 'source-over';
    ctx.restore();

    // -- Horizon line --
    if (CONFIG.horizonEnabled) {
      ctx.strokeStyle = CONFIG.horizonColor;
      ctx.lineWidth = 2;
      ctx.globalAlpha = 0.6;
      ctx.beginPath();
      ctx.moveTo(0, sunY);
      ctx.lineTo(width, sunY);
      ctx.stroke();
      ctx.globalAlpha = 1;
    }

    // -- Ground reflection glow --
    const groundGrad = ctx.createLinearGradient(0, sunY, 0, height);
    const bottomRgb = hexToRgb(CONFIG.sunColorBottom);
    groundGrad.addColorStop(0, `rgba(${bottomRgb.r}, ${bottomRgb.g}, ${bottomRgb.b}, 0.08)`);
    groundGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
    ctx.fillStyle = groundGrad;
    ctx.fillRect(0, sunY, width, height - sunY);

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
