.app :where([class*="bg-gray-9"]):not(button):not(a):not(input):not(select) {
  background-color: transparent !important;
  background-image: none !important;
}

/* Blend chat/folder background images with gradient */
#chat-container .bg-linear-to-t {
  background-image: linear-gradient(
    to top, rgba(10, 10, 46, 0.7), rgba(13, 115, 119, 0.35)
  ) !important;
}

/* Sidebar & input readability */
#sidebar {
  background-color: rgba(10, 10, 46, 0.7) !important;
  backdrop-filter: blur(12px) !important;
}
textarea {
  background-color: rgba(10, 10, 46, 0.5) !important;
  backdrop-filter: blur(8px) !important;

/* Green-line grid */ body {
	background-image: linear-gradient(rgba(26, 255, 26, 0.05) 1px, transparent 1px), linear-gradient(90deg, rgba(26, 255, 26, 0.05) 1px, transparent 1px) !important;
	background-size: 20px 20px !important;
	background-position: center top !important;
}
/* Mono font — set at the root so it inherits (incl. portaled menus) */
html, body {
	font-family: 'JetBrains Mono', 'Monaco', monospace !important;
}
/* Phosphor borders */ .app * {
	border-color: rgba(26, 255, 26, 0.25) !important;
}
input, textarea, #chat-input-container, .markdown-prose {
	background-color: rgba(10, 26, 10, 0.85) !important;
	border: 1px solid rgba(26, 255, 26, 0.35) !important;
}
/* Green accent buttons */ button.bg-blue-500, button.bg-blue-600 {
