dark.canvasScript:
/**
 * Title: Vector Telemetry
 * Description: Industrial flight path vectors and coordinate pips for the Apollo console.
 */

const CONFIG = {
    pathCount: 8,
    pipCount: 20,
    primaryColor: 'rgba(209, 217, 230, 0.15)',
    accentColor: 'rgba(255, 51, 0, 0.3)',
    speed: 0.002
};

let canvas, ctx, w, h;
let paths = [];
let pips = [];

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    paths = [];
    for (let i = 0; i < CONFIG.pathCount; i++) {
        paths.push({
            y: Math.random() * h,
            amp: Math.random() * 100 + 50,
            freq: Math.random() * 0.005 + 0.002,
            offset: Math.random() * Math.PI * 2
        });
    }
    pips = [];
    for (let i = 0; i < CONFIG.pipCount; i++) {
        pips.push({
            x: Math.random() * w, y: Math.random() * h,
            vx: (Math.random() - 0.5) * 0.5,
            vy: (Math.random() - 0.5) * 0.5
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    // Draw Parabolic Vector Paths
    ctx.lineWidth = 1;
    for (let p of paths) {
        ctx.strokeStyle = CONFIG.primaryColor;
        ctx.beginPath();
        for (let x = 0; x < w; x += 10) {
            let y = p.y + Math.sin(x * p.freq + p.offset) * p.amp;
            if (x === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
        }
        ctx.stroke();
        p.offset += CONFIG.speed;
    }

    // Draw Coordinate Pips
    for (let p of pips) {
        p.x += p.vx; p.y += p.vy;
        if (p.x < 0) p.x = w; if (p.x > w) p.x = 0;
        if (p.y < 0) p.y = h; if (p.y > h) p.y = 0;

        ctx.fillStyle = Math.random() > 0.98 ? CONFIG.accentColor : CONFIG.primaryColor;
        ctx.fillRect(p.x, p.y, 2, 2);

        // Subtle labels
        if (Math.random() > 0.999) {
            ctx.font = '8px monospace';
            ctx.fillText(Math.floor(p.x) + ',' + Math.floor(p.y), p.x + 5, p.y);
        }
    }

    requestAnimationFrame(render);
}

