dark.canvasScript:
/**
 * Title: Lidar Topographical Scan
 * Description: A 3D terrain wireframe that warps and reacts to mouse pressure.
 */

const CONFIG = {
    gridRes: 30,         // Resolution of the terrain
    color: 'rgba(255, 95, 0, 0.2)',
    lineColor: 'rgba(255, 95, 0, 0.4)',
    speed: 0.005,
    amplitude: 40,
    mouseForce: 100
};

let canvas, ctx, w, h;
let time = 0;
let mouse = { x: -5000, y: -5000 };

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    time += CONFIG.speed;

    const cellW = w / CONFIG.gridRes;
    const cellH = h / CONFIG.gridRes;

    ctx.strokeStyle = CONFIG.lineColor;
    ctx.lineWidth = 1;

    for (let i = 0; i < CONFIG.gridRes; i++) {
        ctx.beginPath();
        for (let j = 0; j <= CONFIG.gridRes; j++) {
            let x = j * cellW;
            let y = i * cellH;

            // Procedural terrain math
            let noise = Math.sin(j * 0.2 + time) * Math.cos(i * 0.2 + time);
            let z = noise * CONFIG.amplitude;

            // Mouse warping
            let dx = mouse.x - x; let dy = mouse.y - y;
            let dist = Math.hypot(dx, dy);
            if (dist < 200) {
                z -= (1 - dist / 200) * CONFIG.mouseForce;
            }

            ctx.lineTo(x, y + z);
        }
        ctx.stroke();
    }

    // Vertical lines
    for (let j = 0; j < CONFIG.gridRes; j++) {
        ctx.beginPath();
        for (let i = 0; i <= CONFIG.gridRes; i++) {
            let x = j * cellW;
            let y = i * cellH;
            let noise = Math.sin(j * 0.2 + time) * Math.cos(i * 0.2 + time);
            let z = noise * CONFIG.amplitude;
            let dx = mouse.x - x; let dy = mouse.y - y; let dist = Math.hypot(dx, dy);
            if (dist < 200) z -= (1 - dist / 200) * CONFIG.mouseForce;
            ctx.lineTo(x, y + z);
        }
        ctx.stroke();
    }

    requestAnimationFrame(render);
}

