    headColor: '#fff',           // Color of the leading character
    fadeAmount: 0.08,            // Alpha for erasing trails to transparency
    dropSpeed: 1,
    chars: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@#$%^&*()_+'
