dark.canvasScript:
let canvas, ctx, W, H, mouseX = -1, mouseY = -1;
const particles = [];
const MAX = 60;
const CONNECT_DIST = 120;

function createParticle() {
  return {
    x: Math.random() * W,
    y: Math.random() * H,
    r: 1.5 + Math.random() * 2,
    dx: (Math.random() - 0.5) * 0.4,
    dy: (Math.random() - 0.5) * 0.4,
    alpha: 0.4 + Math.random() * 0.4,
    color: ["#eb6f92", "#c4a7e7", "#9ccfd8", "#f6c177", "#e0def4"][Math.random() * 5 | 0],
    pulse: Math.random() * 6.283,
    pulseSpeed: 0.01 + Math.random() * 0.02
  };
}

function init(c, w, h) {
  canvas = c; ctx = c.getContext('2d'); W = w; H = h;
  particles.length = 0;
  for (let i = 0; i < MAX; i++) particles.push(createParticle());
}

function draw() {
  ctx.fillStyle = 'rgba(25, 23, 36, 0.06)';
  ctx.fillRect(0, 0, W, H);
  for (let i = 0; i < particles.length; i++) {
    const a = particles[i];
    a.x += a.dx; a.y += a.dy;
    a.pulse += a.pulseSpeed;
    if (a.x < 0 || a.x > W) a.dx *= -1;
    if (a.y < 0 || a.y > H) a.dy *= -1;
    const glow = 0.5 + 0.5 * Math.sin(a.pulse);
    for (let j = i + 1; j < particles.length; j++) {
      const b = particles[j];
      const dx = a.x - b.x, dy = a.y - b.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < CONNECT_DIST) {
        ctx.beginPath();
        ctx.moveTo(a.x, a.y);
        ctx.lineTo(b.x, b.y);
        ctx.strokeStyle = '#907aa9';
        ctx.globalAlpha = (1 - dist / CONNECT_DIST) * 0.15;
        ctx.stroke();
        ctx.globalAlpha = 1;
      }
    }
    ctx.beginPath();
    ctx.arc(a.x, a.y, a.r + glow, 0, 6.283);
    ctx.fillStyle = a.color;
    ctx.globalAlpha = a.alpha * (0.7 + glow * 0.3);
    ctx.fill();
    ctx.globalAlpha = 1;
  }
  requestAnimationFrame(draw);
}

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = function(e) {
  const { type, canvas: c, width, height, x, y } = e.data;
  switch (type) {
    case 'init': init(c, width, height); draw(); break;
    case 'resize': W = width; H = height; if (canvas) { canvas.width = W; canvas.height = H; } break;
    case 'mousemove': mouseX = x; mouseY = y; break;
  }
};

